import Link from '../../components/Link';
import ScrollContainer from '../../components/ScrollContainer';
import InnerLink from '../../components/InnerLink';
const _not_found = {title: "Unknown", jsx: <><h2 id="magic-rod-not_found-error">Error</h2>
<p>Unable to find the requested magic rod.</p>
</>};
const _rod_of_the_thriceborn_lesser = {title: "Rod of the Thriceborn (lesser)", jsx: <><h2 id="magic-rod-rod_of_the_thriceborn_lesser-rod-of-the-thriceborn">Rod of the Thriceborn</h2>
<p><strong>Sources</strong> <Link to="/source/legacy_of_the_first_world">Legacy of the First World pg. 25</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 2,500 gp (lesser [up to 3rd-level spells]), 6,500 gp (normal [up to 6th-level spells]), 19,500 gp (greater [all spells]); <strong>Weight</strong> 5 lbs.</p>
<p>The wielder of this elongated triangular prism can cast up to three spells per day for which the spell's targets must roll three times for their saving throws and take the middle of the three results, as per <em>threefold sight.</em> A lesser rod of the thriceborn can affect spells up to 3rd level, a rod of the thriceborn can affect spells up to 6th level, and a greater rod of the thriceborn can affect spells up to 9th level. A rod of the thriceborn can't be used in conjunction with metamagic rods or the <Link to="/feat/persistent_spell">Persistent Spell</Link> feat.</p>
<h3 id="magic-rod-rod_of_the_thriceborn_lesser-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/threefold_sight">threefold sight</Link>; <strong>Cost</strong> 1,250 gp (lesser), 3,250 gp (normal), 9,750 (greater)</p>
</>};
const _rod_of_giant_summoning_lesser = {title: "Rod of Giant Summoning (lesser)", jsx: <><h2 id="magic-rod-rod_of_giant_summoning_lesser-rod-of-giant-summoning">Rod of Giant Summoning</h2>
<p><strong>Sources</strong> <Link to="/source/monster_summoners_handbook">Monster Summoner's Handbook pg. 20</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 17th<br/><strong>Slot</strong> none; <strong>Price</strong> 3,000 gp (lesser [up to 3rd-level spells]), 11,000 gp (normal [up to 6th-level spells]), 24,500 gp (greater [all spells]); <strong>Weight</strong> 5 lbs.</p>
<p>This iron rod has long metal flanges, like a mace, which widen as they expand from the handle. The wielder can use the rod up to three times per day to augment her casting of a conjuration (summoning) spell, causing all of her summoned creatures to gain the <Link to="/template/giant">giant</Link> simple template. The lesser rod can be used with spells of 3rd level or lower, the standard rod can be used with spells of 6th level or lower, and the greater rod can be used with spells of 9th level or lower.</p>
<h3 id="magic-rod-rod_of_giant_summoning_lesser-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/feat/augment_summoning">Augment Summoning</Link>, <Link to="/spell/summon_monster_iii">summon monster III</Link> or <Link to="/spell/summon_natures_ally_iii">summon nature's ally III</Link>; <strong>Cost</strong> 1,500 gp (lesser), 5,500 gp (normal), 12,250 gp (greater)</p>
</>};
const _aerialists_rod = {title: "Aerialist's Rod", jsx: <><h2 id="magic-rod-aerialists_rod-aerialists-rod">Aerialist's Rod</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 32</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 3,200 gp; <strong>Weight</strong> 5 lbs.</p>
<p>A small, metal loop caps each end of this well-worn, 2-foot-long brass rod. Pressing on each of three smooth studs on the rod's surface activates a different special ability. Pressing a stud a second time collapses the rod back into its ordinary form.</p>
<p><strong>Balancing Pole:</strong> The rod extends to 7 feet in length and grants its holder a +5 competence bonus on <Link to="/skill/acrobatics">Acrobatics</Link> checks and a +3 enhancement bonus on Reflex saving throws. The user must hold the rod in both hands to gain these bonuses, and they apply only on checks and saving throws related to maintaining balance. In this form, the rod also acts as a <Link to="/rule/masterwork_w">masterwork</Link> <Link to="/eq-weapon/quarterstaff">quarterstaff</Link>.</p>
<p><strong>Tightrope:</strong> A line of rope lashes out from each end of the rod, anchoring to create a horizontal tightrope up to 100 feet long. Characters can traverse the tightrope by hanging below it with a successful DC 15 <Link to="/skill/climb">Climb</Link> check, or walking atop it with a successful DC 20 Acrobatics check.</p>
<p><strong>Trapeze:</strong> Two lines of rope fly from the ends of the rod and anchor in a ceiling up to 40 feet overhead. Using the trapeze requires a successful DC 10 Acrobatics check and allows the user to traverse gaps up to 50 feet wide. If the user is trying to go farther than 50 feet, she can attempt to jump upon releasing her grip. The trapeze counts as a running start for the purposes of performing a long jump, and grants the user a +5 competence bonus on Acrobatics checks to determine how far she can jump. When the user is outdoors, this ability functions only if there are branches, buildings, or other overhangs to which the trapeze can attach.</p>
<h3 id="magic-rod-aerialists_rod-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/animate_rope">animate rope</Link>, <Link to="/spell/cats_grace">cat's grace</Link>; <strong>Cost</strong> 1,600 gp</p>
</>};
const _chastising_baton = {title: "Chastising Baton", jsx: <><h2 id="magic-rod-chastising_baton-chastising-baton">Chastising Baton</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_high_court">Heroes of the High Court pg. 30</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 7th<br/><strong>Slot</strong> none; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This short metal rod is etched with the outlines of various weapons and is usually owned by strong-armed rulers who keep a tight rein on their nation's military. A chastising baton adds 1 to the saving throw DC of any compulsion spell cast by the wielder and adds the <Link to="/spelldef/pain">pain</Link> descriptor to the spell. Creatures that succeed at a Will save against a compulsion spell cast by the wielder are racked with pain, taking 1d6 points of nonlethal damage and becoming <Link to="/misc/sickened">sickened</Link> for 1 round.</p>
<h3 id="magic-rod-chastising_baton-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/pain_strike">pain strike</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _immovable_rod = {title: "Immovable Rod", jsx: <><h2 id="magic-rod-immovable_rod-immovable-rod">Immovable Rod</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 178</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 485</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> none; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This rod looks like a flat iron bar with a small button on one end. When the button is pushed (a move action), the rod does not move from where it is, even if staying in place defies gravity. Thus, the owner can lift or place the rod wherever he wishes, push the button, and let go. Several immovable rods can even make a ladder when used together (although only two are needed). An immovable rod can support up to 8,000 pounds before falling to the ground. If a creature pushes against an immovable rod, it must succeed at a DC 30 Strength check to move the rod up to 10 feet in a single round.</p>
<h3 id="magic-rod-immovable_rod-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/levitate">levitate</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _refocusing_rod = {title: "Refocusing Rod", jsx: <><h2 id="magic-rod-refocusing_rod-refocusing-rod">Refocusing Rod</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 254</Link><br/><strong>Aura</strong> moderate (no school); <strong>CL</strong> 10th<br/><strong>Slot</strong> none; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Once per day, a refocusing rod allows an <Link to="/class/occultist">occultist</Link> to transfer mental focus using the shift focus class feature without losing any points of focus. He can move focus from one implement into the rod, and then from the rod into another implement, by spending twice as long as it normally takes him to shift focus (because he's making two transfers). The occultist must transfer the focus from the rod within 10 minutes or the focus is lost.</p>
<p>If an occultist chooses a refocusing rod as one of his implements for the day, he can instead use this ability to transfer focus into the rod and leave it there or transfer focus he already stored in the rod into another implement. In either of these cases, no points of focus are lost in the transfer and it takes the normal amount of time to shift focus instead of twice as long. If the refocusing rod is not one of the occultist's implements for the day, mental focus stored in it can't be used for any purpose except transference to another implement.</p>
<p>Any mental focus transferred into the rod still belongs to the occultist who transferred it. The rod can't be used to transfer mental focus between two users.</p>
<h3 id="magic-rod-refocusing_rod-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, creator must be a 10th-level occultist; <strong>Cost</strong> 2,500 gp</p>
</>};
const _utilitarian_rod = {title: "Utilitarian Rod", jsx: <><h2 id="magic-rod-utilitarian_rod-utilitarian-rod">Utilitarian Rod</h2>
<p><strong>Sources</strong> <Link to="/source/faction_guide">Faction Guide pg. 60</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> none; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>Created by the Arcanamirium, this plain wooden rod is capped with steel, with 10 buttons along its length; it looks rugged and is usually scratched and stained. Pushing any of the buttons is an action equivalent to drawing a weapon. Unless otherwise stated, pressing a button a second time reverts the rod to its basic form. The following functions have no limit on the number of times they can be employed.</p>
<p><strong>Brace/jack:</strong> The end caps flatten into 2-foot-diameter discs and the wooden haft extends up to 10 feet, creating a brace for a tunnel ceiling or lifting a heavy object 10 feet into the air.</p>
<p><strong>Bridge:</strong> The rod flattens and extends to 1 foot wide, 1 inch thick, and 12 feet long. This form can support 4,000 pounds.</p>
<p><strong>Climbing pole/ladder:</strong> A spike that can anchor in stone extrudes from one end, while the other sprouts three sharp hooks. The rod lengthens to anywhere between 5 and 50 feet in a single round. Horizontal bars 3 inches long fold out from the sides, 1 foot apart, in staggered progression. The rod is firmly held by the spike and hooks and can bear up to 4,000 pounds.</p>
<p><strong>Crowbar:</strong> This functions like a normal <Link to="/eq-misc/crowbar">crowbar</Link>.</p>
<p><strong>Drill:</strong> One metal cap extends to a drill-like point and begins to spin, easily drilling a 3-inch-diameter hole through 3 feet of wood or 1 foot of stone per minute.</p>
<p><strong>Mallet:</strong> Though not intended as a weapon, a character can attack with the rod in this form as if it were a Medium <Link to="/eq-weapon/warhammer">warhammer</Link> with a -2 penalty.</p>
<p><strong>Portable ram:</strong> This functions like a normal <Link to="/eq-misc/portable_ram">portable ram</Link>, except up to three people are needed to help the wielder.</p>
<p><strong>Saw:</strong> This works like a normal <Link to="/eq-misc/two_person_saw">two-person saw</Link>.</p>
<p><strong>Shovel:</strong> Pressing this button makes the rod cycle between a short-handled <Link to="/eq-misc/shovel">shovel</Link>, a long-handled shovel, and its basic form.</p>
<p><strong>Wedge:</strong> One metal cap extends to form a flat chisel shape, such as for cutting wood or breaking stone (normally a hammer or mallet is used with it for this task).</p>
<h3 id="magic-rod-utilitarian_rod-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/fabricate">fabricate</Link>, <Link to="/spell/polymorph_any_object">polymorph any object</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _recondite_rod_lesser = {title: "Recondite Rod (lesser)", jsx: <><h2 id="magic-rod-recondite_rod_lesser-recondite-rod">Recondite Rod</h2>
<p><strong>Sources</strong> <Link to="/source/psychic_anthology">Psychic Anthology pg. 8</Link><br/><strong>Aura</strong> strong (no school); <strong>CL</strong> 17th<br/><strong>Slot</strong> none; <strong>Price</strong> 5,000 gp (lesser [up to 3rd-level spells]), 18,000 gp (normal [up to 6th-level spells]), 40,500 gp (greater [all spells]); <strong>Weight</strong> 5 lbs.</p>
<p>This odd, 2-foot-long rod appears to be made out of solidified ectoplasm shot through with energy that pulses brightly at regular intervals, almost like a heartbeat. Three times per day, this rod allows its wielder to cast a psychic spell that could be undercast (such as <Link to="/spell/ego_whip_1">ego whip</Link> or <em>mind thrust</em>) at 1 level higher, even if the wielder doesn't know the higher-level spell or can't cast spells of that level. The spell uses the same spell slot and save DC as that of the lower-level spell, but creates the effects of the higher-level spell. For example, the wielder could use this rod to cast <Link to="/spell/mind_thrust_i">mind thrust I</Link>, with the effect of <Link to="/spell/mind_thrust_ii">mind thrust II</Link>. This rod can't be used to cast the highest-level spell of a particular group. The wielder must the able to cast the lower-level spell to use this rod. Using this rod is part of the action of casting the modified spell. A lesser recondite rod can be used with spells of 3rd level or lower. A recondite rod can be used with spells of 6th level or lower. A greater recondite rod can be used with spells of 8th level or lower.</p>
<h3 id="magic-rod-recondite_rod_lesser-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/feat/empower_spell">Empower Spell</Link>, the creator must know at least one spell that can be undercast; <strong>Cost</strong> 2,500 gp (lesser), 9,000 gp (normal), 20,250 gp (greater)</p>
</>};
const _rod_of_thunderous_force = {title: "Rod of Thunderous Force", jsx: <><h2 id="magic-rod-rod_of_thunderous_force-rod-of-thunderous-force">Rod of Thunderous Force</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 185</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 5,400 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This mahogany rod is etched with the image of whirling storm clouds. Once per day on command, the wielder can slam the rod against the ground, releasing a concussive wave of sonic and force energy. This creates a 20-foot radius <Link to="/misc/burst">burst</Link> centered on the wielder. While it causes no damage, those within the burst must succeed at a DC 19 Fortitude save or fall <Link to="/rule/prone">prone</Link> and be <Link to="/misc/deafened">deafened</Link> for 1d4 rounds. The wielder is unaffected by this blast. This effect is a force and sonic effect.</p>
<h3 id="magic-rod-rod_of_thunderous_force-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/blindness_deafness">blindness/deafness</Link>, <Link to="/spell/wall_of_force">wall of force</Link>; <strong>Cost</strong> 2,700 gp</p>
</>};
const _backbiters_focus = {title: "Backbiter's Focus", jsx: <><h2 id="magic-rod-backbiters_focus-backbiters-focus">Backbiter's Focus</h2>
<p><strong>Sources</strong> <Link to="/source/the_harrow_handbook">The Harrow Handbook pg. 30</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 7th<br/><strong>Slot</strong> none; <strong>Price</strong> 7,800 gp; <strong>Weight</strong> 1 lb.</p>
<p>This small <Link to="/eq-material/darkwood">darkwood</Link> rod is adorned with a carving of a figure whose own weapon is curled backward as if to strike the figure. Three times per day, the user can speak the rod's command word to curse a single manufactured weapon within 30 feet. If the weapon is magical, it can attempt a DC 16 Will save to avoid the curse. Whenever the cursed weapon damages a creature, it deals half as much damage to its wielder as well; only the weapon's base damage and the wielder's Strength bonus are factored into this damage - bonus damage from a magic weapon's special abilities, from its wielder's class features and feats, or from other effects are not factored into the damage dealt to the wielder. This is a curse effect that lasts for 7 rounds.</p>
<h3 id="magic-rod-backbiters_focus-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/bestow_curse">bestow curse</Link>; <strong>Cost</strong> 4,900 gp</p>
</>};
const _rod_of_mortared_walls = {title: "Rod of Mortared Walls", jsx: <><h2 id="magic-rod-rod_of_mortared_walls-rod-of-mortared-walls">Rod of Mortared Walls</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_95_anvil_of_fire">Pathfinder #95: Anvil of Fire pg. 25</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> none; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This carved stone rod is capped with a flat metal trowel blade. The rod can be used three times per day, in any combination of the following abilities.</p>
<ul>
<li>The blade end can produce enough mortar each day to hold together a brick or stone wall 10 feet long, 10 feet high, and 1 foot thick, which takes approximately 8 hours of work (the rod does not create the other building materials, such as bricks or stones). The mortar fully cures after 8 hours. The blade produces mortar as needed as part of normal use (instead of all at once).</li>
<li>If a command word is spoken and the butt end is pointed at a piece of rock or stone weighing up to 1,000 pounds (approximately a 24-inch cube), the wielder can move that stone vertically as if using <Link to="/spell/levitate">levitate</Link>, and can move the levitating stone horizontally 5 feet as a move action. Each such use of the rod lasts up to 10 minutes, and the wielder can divide this duration among multiple stones (but can move only one stone at a time).</li>
<li>If a second command word is spoken, the wielder can draw a line on the ground with the trowel blade, and over the course of the next 10 rounds, the line grows a <em>wall of stone</em> at a rate of 1 foot per round. The wall is masonry instead of natural stone. The wall grows to a maximum of 10 feet high and 10 feet long. It merges with existing masonry, or creates a smooth seam against natural stone or a wooden frame (such as a doorway). This ability functions only if the floor is stone (whether natural or worked).</li>
</ul>
<h3 id="magic-rod-rod_of_mortared_walls-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/soften_earth_and_stone">soften earth and stone</Link>, <Link to="/spell/wall_of_stone">wall of stone</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _crypt_rod = {title: "Crypt Rod", jsx: <><h2 id="magic-rod-crypt_rod-crypt-rod">Crypt Rod</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_139_the_dead_road">Pathfinder #139: The Dead Road pg. 64</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 8,500 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This 3-foot-long iron rod has a flanged, conical head and strikes as a +1 <Link to="/eq-weapon/light_mace">light mace</Link>. On command when held in hand, the rod points in the direction of the closest grave, tomb, or cairn within 500 feet. If the wielder concentrates on a specific type or subtype of creature, the rod identifies only gravesites that hold the remains of that type of creature. The rod can search for the remains of a specific individual if the wielder carries an item that the individual owned in life.</p>
<h3 id="magic-rod-crypt_rod-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/locate_object">locate object</Link>; <strong>Cost</strong> 4,250 gp</p>
</>};
const _rod_of_ice = {title: "Rod of Ice", jsx: <><h2 id="magic-rod-rod_of_ice-rod-of-ice">Rod of Ice</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 182</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 8,500 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This rod looks like a long sliver of ice and is cold to the touch, but deals no cold damage to its wielder. The wearer can use the rod to make a melee touch attack that deals 1d4 points of cold damage to any creature struck. Also, once per day on command, the wielder can touch the rod to the ground to create a 30-foot cone of ice that encrusts the earth, affecting the area as per the spell <Link to="/spell/grease">grease</Link>.</p>
<h3 id="magic-rod-rod_of_ice-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/cone_of_cold">cone of cold</Link>; <strong>Cost</strong> 4,250 gp</p>
</>};
const _inviolate_marker = {title: "Inviolate Marker", jsx: <><h2 id="magic-rod-inviolate_marker-inviolate-marker">Inviolate Marker</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_sands">People of the Sands pg. 29</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> none; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This unusual type of <Link to="/magic-rod/immovable_rod">immovable rod</Link> has a button near each end, and it can be activated only by two separate creatures, each one pressing a button while speaking a different command word. Once set in place, it can only be moved by the same method. A creature using a Strength check to move the inviolate marker risks being affected by a <em>bestow curse</em> effect (-6 Str; Will DC 16 negates and grants the creature immunity to the curse effect for 24 hours).</p>
<p>An inviolate marker projects an illusory banner or crest from each side, each chosen by the creature that activated it, and is used to demarcate territorial boundaries. If an inviolate marker would be buried by a change in the landscape or environment, the marker teleports to the surface of the newly formed terrain in order to maintain its position relative to the new terrain.</p>
<h3 id="magic-rod-inviolate_marker-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/bestow_curse">bestow curse</Link>, <Link to="/spell/levitate">levitate</Link>, <Link to="/spell/silent_image">silent image</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _rod_of_metal_and_mineral_detection = {title: "Rod of Metal and Mineral Detection", jsx: <><h2 id="magic-rod-rod_of_metal_and_mineral_detection-rod-of-metal-and-mineral-detection">Rod of Metal and Mineral Detection</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 182</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 485</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 10,500 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This rod is valued by treasure hunters and miners alike, for it pulses and hums in the wielder's hand in the proximity of metal. As the wearer aims the rod, the pulsations grow more noticeable as it points to the largest mass of metal within 30 feet. However, the wielder can also concentrate on a specific metal or mineral. If the specific mineral is within 30 feet, the rod points to any places it is located, and the rod wielder knows the approximate quantity as well. If more than one deposit of the specified metal or mineral is within range, the rod points to the largest cache first. Each operation requires a full-round action.</p>
<h3 id="magic-rod-rod_of_metal_and_mineral_detection-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/locate_object">locate object</Link>; <strong>Cost</strong> 5,250 gp</p>
</>};
const _rod_of_cancellation = {title: "Rod of Cancellation", jsx: <><h2 id="magic-rod-rod_of_cancellation-rod-of-cancellation">Rod of Cancellation</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 181</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 485</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 17th<br/><strong>Slot</strong> none; <strong>Price</strong> 11,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This dreaded rod is a bane to magic items, for its touch drains an item of all magical properties. The item touched must make a successful DC 23 Will save to prevent the rod from draining it. If a creature is holding it at the time, then the item can use the holder's Will save bonus in place of its own if the holder's is better. In such cases, contact is made by making a melee touch attack roll. Upon draining an item, the rod becomes brittle and cannot be used again. Drained items are only restorable by a <Link to="/spell/wish">wish</Link> or <Link to="/spell/miracle">miracle</Link> spell. If a <Link to="/magic-artifact/sphere_of_annihilation">sphere of annihilation</Link> and a rod of cancellation negate each other, nothing can restore either of them.</p>
<h3 id="magic-rod-rod_of_cancellation-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/mages_disjunction">mage's disjunction</Link>; <strong>Cost</strong> 5,500 gp</p>
</>};
const _rod_of_grasping_hexes = {title: "Rod of Grasping Hexes", jsx: <><h2 id="magic-rod-rod_of_grasping_hexes-rod-of-grasping-hexes">Rod of Grasping Hexes</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 220</Link><br/><strong>Aura</strong> strong (no school); <strong>CL</strong> 17th<br/><strong>Slot</strong> none; <strong>Price</strong> 11,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This rod is crafted from a gnarled branch covered in sharp thorns. Three times per day when a wielder of this rod uses a hex (but not an advanced hex or grand hex), she can use this rod's power to double the range of the hex, so long as the hex has a range measured in feet.</p>
<h3 id="magic-rod-rod_of_grasping_hexes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/feat/reach_spell">Reach Spell</Link>, creator must possess the hex class feature; <strong>Cost</strong> 5,500 gp</p>
</>};
const _rod_of_interminable_hexes = {title: "Rod of Interminable Hexes", jsx: <><h2 id="magic-rod-rod_of_interminable_hexes-rod-of-interminable-hexes">Rod of Interminable Hexes</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 220</Link><br/><strong>Aura</strong> strong (no school); <strong>CL</strong> 17th<br/><strong>Slot</strong> none; <strong>Price</strong> 11,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>Three times per day when a wielder of this rod uses a hex (but not an advanced hex or grand hex), she can use this rod's power to double the duration of the hex, so long as the hex's normal duration is longer than 1 round. When augmented with this rod, a hex that might have a longer duration if a target fails its save but only a 1-round duration if the target succeeds at its save (such as evil eye) still has only a 1-round duration against a target that succeeds at its save.</p>
<h3 id="magic-rod-rod_of_interminable_hexes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/feat/extend_spell">Extend Spell</Link>, creator must possess the hex class feature; <strong>Cost</strong> 5,500 gp</p>
</>};
const _rod_of_burning_blood = {title: "Rod of Burning Blood", jsx: <><h2 id="magic-rod-rod_of_burning_blood-rod-of-burning-blood">Rod of Burning Blood</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 93</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 10th<br/><strong>Slot</strong> none; <strong>Price</strong> 11,050 gp; <strong>Weight</strong> 4 lbs.</p>
<p>This rod of blackened iron is inset with rubies and functions as a +1 <Link to="/magic-enh/cunning">cunning</Link> <Link to="/eq-weapon/light_mace">light mace</Link>. <Link to="/eq-weapon/unholy_water">Unholy water</Link> poured over the rod is absorbed, giving the rod 1 charge per vial. When the rod strikes a creature, the wielder can expend 1 charge from the rod to spray the creature with burning blood from the weapon's head. This burning blood deals 1d6 points of damage (half fire, half unholy).</p>
<p>Alternatively, the wielder can expend 5 charges at once to create a spray of burning blood in a 15-foot cone. Creatures in the area take 5d4 points of damage (half fire, half unholy; Reflex DC 17 half). The rod can hold at most 10 charges at any one time. Charging the rod with unholy water is a standard action that provokes attacks of opportunity.</p>
<h3 id="magic-rod-rod_of_burning_blood-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/flame_strike">flame strike</Link>, <Link to="/spell/true_strike">true strike</Link>; <strong>Cost</strong> 5,525 gp</p>
</>};
const _conduit_rod = {title: "Conduit Rod", jsx: <><h2 id="magic-rod-conduit_rod-conduit-rod">Conduit Rod</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 178</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 12th<br/><strong>Slot</strong> none; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This stout, dense rod is always constructed of highly conductive metal, shot through with web-like veins of white or yellow glass. While a creature holds a conduit rod, she gains electricity resistance 5 as a constant effect as well as a +1 bonus to her effective caster level when casting any spell with the electricity descriptor.</p>
<p>Once per day as a free action, when the wielder of a conduit rod casts a spell with the electricity descriptor, she can teleport anywhere that spell's effect, but is otherwise unaffected by the spell.</p>
<h3 id="magic-rod-conduit_rod-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/dimension_door">dimension door</Link>, <Link to="/spell/lightning_bolt">lightning bolt</Link>, <Link to="/spell/resist_energy">resist energy</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _grounding_rod = {title: "Grounding Rod", jsx: <><h2 id="magic-rod-grounding_rod-grounding-rod">Grounding Rod</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 178</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> 10 lbs.</p>
<p>This 6-foot-long silver rod is capped with a copper ball at one end, and a multipronged iron spike at the other. Three times per day, the spiked end can be driven into sand, mud, or loose earth as a move action, into dense soil or loose gravel as a standard action, or into stone or harder materials as a full-round action. Once anchored, the rod emits a field that inhibits electrical charges within a 40-foot radius. All creatures within this radius gain resistance 5 to electricity, and anyone attempting to cast a spell with the electricity descriptor must make a caster level check (DC 16) or lose the spell.</p>
<p>Removing the rod from the ground and deactivating it requires the same type of action as anchoring it.</p>
<h3 id="magic-rod-grounding_rod-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/dispel_magic">dispel magic</Link>, <Link to="/spell/lightning_bolt">lightning bolt</Link>, <Link to="/spell/resist_energy">resist energy</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _rod_of_spellsight = {title: "Rod of Spellsight", jsx: <><h2 id="magic-rod-rod_of_spellsight-rod-of-spellsight">Rod of Spellsight</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 14</Link><br/><strong>Aura</strong> strong divination; <strong>CL</strong> 13th<br/><strong>Slot</strong> none; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> 6 lbs.</p>
<p>This beautiful ivory rod is embedded with countless sapphires and covered with intricate designs inlaid in silver. The vision of a rod of spellsight's wielder is unaffected by any magical cloud, fog, mist, smoke, or vapor effect. This allows the wielder to see through the effects of <Link to="/spell/fog_cloud">fog cloud</Link>, <Link to="/spell/obscuring_mist">obscuring mist</Link>, and even <Link to="/spell/incendiary_cloud">incendiary cloud</Link>. The rod does not protect the wearer against blinding effects such as <Link to="/spell/blindness_deafness">blindness/deafness</Link> or the blinding effect of <Link to="/spell/glitterdust">glitterdust</Link>.</p>
<h3 id="magic-rod-rod_of_spellsight-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/gust_of_wind">gust of wind</Link>, <Link to="/spell/true_seeing">true seeing</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _rod_of_the_wayang = {title: "Rod of the Wayang", jsx: <><h2 id="magic-rod-rod_of_the_wayang-rod-of-the-wayang">Rod of the Wayang</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 185</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 8th<br/><strong>Slot</strong> none; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This rod is lacquered jet black, covered with bright white runes, and capped with crown of jagged smoky quartz. When the rod's wielder casts a spell of the shadow subschool, she increases the DC of that spell's saving throw by 1. Furthermore, once per day on command, wielder can treat positive and negative energy effects as if she were an undead creature, taking damage from positive energy and healing damage from negative energy. This ability lasts for 1 minute unless dismissed as a free action.</p>
<h3 id="magic-rod-rod_of_the_wayang-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/greater_shadow_conjuration">greater shadow conjuration</Link>, <Link to="/spell/greater_shadow_evocation">greater shadow evocation</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _rod_of_wonder = {title: "Rod of Wonder", jsx: <><h2 id="magic-rod-rod_of_wonder-rod-of-wonder">Rod of Wonder</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 185</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 485</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 10th<br/><strong>Slot</strong> none; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>A rod of wonder is a strange and unpredictable device that randomly generates any number of weird effects each time it is used. Activating the rod is a standard action. Typical powers of the rod include the following.</p>
<ScrollContainer id="magic-rod-rod_of_wonder--table-0"><table>
<thead>
<tr>
<th>d%</th>
<th>Wondrous Effect</th>
</tr>
</thead>
<tbody><tr>
<td>01-05</td>
<td>Target affected by <Link to="/spell/slow">slow</Link> for 10 rounds (Will DC 15 negates).</td>
</tr>
<tr>
<td>06-10</td>
<td><Link to="/spell/faerie_fire">Faerie fire</Link> surrounds the target.</td>
</tr>
<tr>
<td>11-15</td>
<td>Deludes the wielder for 1 round into believing the rod functions as indicated by a second die roll (no save).</td>
</tr>
<tr>
<td>16-20</td>
<td><Link to="/spell/gust_of_wind">Gust of wind</Link>, but at windstorm force (Fortitude DC 14 negates).</td>
</tr>
<tr>
<td>21-25</td>
<td>Wielder learns the target's surface thoughts (as with <Link to="/spell/detect_thoughts">detect thoughts</Link>) for 1d4 rounds (no save).</td>
</tr>
<tr>
<td>26-30</td>
<td><Link to="/spell/stinking_cloud">Stinking cloud</Link> appears at 30-foot range (Fortitude DC 15 negates).</td>
</tr>
<tr>
<td>31-33</td>
<td>Heavy rain falls for 1 round in 60-foot radius centered on the rod wielder.</td>
</tr>
<tr>
<td>34-36</td>
<td>Summons an animal - a <Link to="/monster/rhinoceros">rhinoceros</Link> (01-25 on d%), <Link to="/monster/elephant">elephant</Link> (26-50), or <Link to="/monster/mouse">mouse</Link> (51-100).</td>
</tr>
<tr>
<td>37-46</td>
<td><Link to="/spell/lightning_bolt">Lightning bolt</Link> (70 foot long, 5 foot wide), 6d6 points of damage (Reflex DC 15 half).</td>
</tr>
<tr>
<td>47-49</td>
<td>A stream of 600 large <Link to="/monster/butterfly">butterflies</Link> pours forth and flutters around for 2 rounds, blinding everyone within 25 foot (Reflex DC 14 negates).</td>
</tr>
<tr>
<td>50-53</td>
<td>Target is affected by <Link to="/spell/enlarge_person">enlarge person</Link> if within 60 feet of rod (Fortitude DC 13 negates).</td>
</tr>
<tr>
<td>54-58</td>
<td><Link to="/spell/darkness">Darkness</Link>, 30-foot-diameter hemisphere, centered 30 feet away from rod.</td>
</tr>
<tr>
<td>59-62</td>
<td>Grass grows in 160-square-foot area before the rod, or grass existing there grows to 10 times its normal size.</td>
</tr>
<tr>
<td>63-65</td>
<td>Any nonliving object of up to 1,000 pounds of mass and up to 30 cubic feet in size turns ethereal.</td>
</tr>
<tr>
<td>66-69</td>
<td>Reduce wielder two size categories (no save) for 1 day.</td>
</tr>
<tr>
<td>70-79</td>
<td><Link to="/spell/fireball">Fireball</Link> at target or 100 feet straight ahead, 6d6 points of damage (Reflex DC 15 half).</td>
</tr>
<tr>
<td>80-84</td>
<td><Link to="/spell/invisibility">Invisibility</Link> covers the rod's wielder.</td>
</tr>
<tr>
<td>85-87</td>
<td>Leaves grow from the target if within 60 feet of the rod. These last 24 hours.</td>
</tr>
<tr>
<td>88-90</td>
<td>10-40 gems, value 1 gp each, shoot forth in a 30-foot-long stream. Each gem deals 1 point of damage to any creature in its path: roll 5d4 for the number of hits and divide them among the available targets.</td>
</tr>
<tr>
<td>91-95</td>
<td>Shimmering colors dance and play over a 40-foot by-30-foot area in front of rod. Creatures therein are <Link to="/misc/blinded">blinded</Link> for 1d6 rounds (Fortitude DC 15 negates).</td>
</tr>
<tr>
<td>96-97</td>
<td>Wielder (50% chance) or the target (50% chance) turns permanently blue, green, or purple (no save).</td>
</tr>
<tr>
<td>98-100</td>
<td><Link to="/spell/flesh_to_stone">Flesh to stone</Link> (or <Link to="/spell/stone_to_flesh">stone to flesh</Link> if the target is stone already) if the target is within 60 feet (Fortitude DC 18 negates).</td>
</tr>
</tbody></table></ScrollContainer>
<h3 id="magic-rod-rod_of_wonder-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/confusion">confusion</Link>, creator must be chaotic; <strong>Cost</strong> 6,000 gp</p>
</>};
const _rod_of_animal_training = {title: "Rod of Animal Training", jsx: <><h2 id="magic-rod-rod_of_animal_training-rod-of-animal-training">Rod of Animal Training</h2>
<p><strong>Sources</strong> <Link to="/source/animal_archive">Animal Archive pg. 27</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 12,300 gp; <strong>Weight</strong> 5 lbs.</p>
<p>The head of this bronze scepter is shaped like a roaring lion leaping forward. When held by a creature with no ranks in the <Link to="/skill/handle_animal">Handle Animal</Link> skill, this rod allows the wielder to teach <Link to="/ability/animal_tricks">tricks</Link> to any animal with an Intelligence score of 1 or 2 as though the wielder were trained in the use of that skill. Regardless of whether the wielder of a rod of animal training has ranks in Handle Animal, she gains a +5 competence bonus on Handle Animal checks to teach a trick to an animal or to train an animal for a general purpose, and the wielder can use charm animal (DC 11) as a spell-like ability three times per day.</p>
<h3 id="magic-rod-rod_of_animal_training-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/charm_animal">charm animal</Link>; <strong>Cost</strong> 6,150 gp</p>
</>};
const _rod_of_subtle_menace = {title: "Rod of Subtle Menace", jsx: <><h2 id="magic-rod-rod_of_subtle_menace-rod-of-subtle-menace">Rod of Subtle Menace</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 18</Link><br/><strong>Aura</strong> faint enchantment and transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 12,305 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This crude shaft of blackened steel functions as a +1 <Link to="/eq-weapon/light_mace">light mace</Link>. Those who can see the wielder of the rod feel a vague sense of being in danger. This ominous aura is faint but encourages others to avoid angering the wielder, although they may not realize why. When holding the rod in her hand, the wielder can attempt an Intimidate check in place of a Diplomacy check when trying to gather information and always counts as larger than its target for the purpose of Intimidate checks.</p>
<h3 id="magic-rod-rod_of_subtle_menace-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/bane">bane</Link>; <strong>Cost</strong> 6,152 gp</p>
</>};
const _rod_of_the_python = {title: "Rod of the Python", jsx: <><h2 id="magic-rod-rod_of_the_python-rod-of-the-python">Rod of the Python</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 184</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 485</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> none; <strong>Price</strong> 13,000 gp; <strong>Weight</strong> 10 lbs.</p>
<p>Unlike with most rods, one end of this rod curls and twists back on itself in a crook - the tip of this crook sometimes looks like the head of a snake. The rod itself is about 4 feet long and weighs 10 pounds. It strikes as a +1/+1 <Link to="/eq-weapon/quarterstaff">quarterstaff</Link>. If the user throws the rod to the ground (a standard action), it grows to become a <Link to="/monster/constrictor_snake">constrictor snake</Link> by the end of the round. The python obeys all commands of the owner. (In animal form, it retains the +1 enhancement bonus on attack and damage rolls possessed by the rod form.) The serpent returns to rod form (a full-round action) whenever the wielder desires, or whenever it moves farther than 100 feet from the owner. If the snake form is slain, it returns to rod form and cannot be activated again for 3 days. A rod of the python only functions if the possessor is good.</p>
<h3 id="magic-rod-rod_of_the_python-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/baleful_polymorph">baleful polymorph</Link>, creator must be good; <strong>Cost</strong> 6,500 gp</p>
</>};
const _trap_stealers_rod = {title: "Trap-Stealer's Rod", jsx: <><h2 id="magic-rod-trap_stealers_rod-trap-stealers-rod">Trap-Stealer's Rod</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 187</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 15th<br/><strong>Slot</strong> none; <strong>Price</strong> 13,500 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This sturdy iron rod is forged with pronounced angles to allow for strong gripping, inscribed with images and sayings of trickster figures from myths and common folklore. Hooked at one end, a trap-stealer's rod functions as an exceptional <Link to="/eq-misc/crowbar">crowbar</Link>, granting the user a +4 circumstance bonus on Strength checks made to force open a door or chest when using it to do such.</p>
<p>In addition, on command, the wielder can transform the rod into a magical set of <Link to="/eq-misc/thieves_tools">thieves' tools</Link>. Using these grant a +4 competence bonus on <Link to="/skill/disable_device">Disable Device</Link> checks. The wielder can transform these tools into the rod again with a command.</p>
<p>Lastly, if the rod's bearer successfully disables a trap with the thieves' tools and beats the DC to disable the trap by 5 or more, he can magically steal the disabled trap. A stolen trap disappears from the surrounding area, siphoned into extradimensional space that is connected to the rod. Terrain around the trap reworks itself as if the trap never had existed, though doorways and portals that supported a trap remain unaffected. At any time during the next 24 hours, the rod's wielder can place the stored trap in a new location where it operates as normal. The new location must be able to support the trap's placement; for example a stolen pit trap could be taken from a dungeon floor and replaced on a dirt road, but not upon the surface of a river or lake, and the effectiveness of the placement is subject to GM discretion. Placing a stolen trap into a location that does not support it wastes the effect and magically transports the trap back to its original location. Whether successfully placed into a new location or not, a stolen trap returns to its original location after 24 hours. This ability functions once per day.</p>
<h3 id="magic-rod-trap_stealers_rod-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/create_pit">create pit</Link>, <Link to="/spell/knock">knock</Link>, <Link to="/spell/plane_shift">plane shift</Link>; <strong>Cost</strong> 6,750 gp</p>
</>};
const _rod_of_the_uraeus = {title: "Rod of the Uraeus", jsx: <><h2 id="magic-rod-rod_of_the_uraeus-rod-of-the-uraeus">Rod of the Uraeus</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_81_shifting_sands">Pathfinder #81: Shifting Sands pg. 59</Link>, <Link to="/source/osirion_land_of_the_pharaohs">Osirion, Land of the Pharaohs pg. 25</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 8th<br/><strong>Slot</strong> rod; <strong>Price</strong> 14,400 gp; <strong>Weight</strong> 4 lbs.</p>
<p>This rod is fashioned in the form of a uraeus, the legendary two-headed winged cobra that is the symbol of the Ancient Osirian deity <Link to="/faith/wadjet">Wadjet</Link>, patron of Osirion and the goddess of good serpents, the River Sphinx, and wisdom. The priesthood of Wadjet is credited with creating the first rods of the uraeus, but others have since replicated the feat.</p>
<p>A rod of the uraeus can be wielded as a +1 <Link to="/eq-weapon/light_mace">light mace</Link>. When holding the rod, the wielder gains a +2 resistance bonus on Reflex saves and a +5 competence bonus on Sense Motive checks. The wielder can fire a 30-foot line of stinging poison from the rod up to twice per day (once for each head of the uraeus). A creature in the area of effect can avoid the poison with a successful DC 13 Reflex save. On a failed save, a creature is <Link to="/misc/blinded">blinded</Link> and <Link to="/rule/paralyzed">paralyzed</Link> for 8 rounds. Each round on its turn, an affected creature may attempt a DC 13 Fortitude save to end the blindness and paralysis effects. A rod of the uraeus functions only if its possessor is lawful.</p>
<h3 id="magic-rod-rod_of_the_uraeus-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/poison">poison</Link>, <Link to="/spell/resistance">resistance</Link>, creator must have 5 ranks in Sense Motive; <strong>Cost</strong> 7,200 gp</p>
</>};
const _rod_of_balance = {title: "Rod of Balance", jsx: <><h2 id="magic-rod-rod_of_balance-rod-of-balance">Rod of Balance</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 180</Link><br/><strong>Aura</strong> faint and transmutation abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This short, slender rod appears to be crafted from solid iron, though it is incredibly light. In this shortened form, the rod has no powers. However, when the wielder pushes a small button on one end of the rod (a move action), the rod springs open to a 5-foot length, and its powers become available for use.</p>
<p>Once extended, the rod possesses several powers that add to the wielder's acrobatic abilities. The wielder of the rod receives a +10 competence bonus on all <Link to="/skill/acrobatics">Acrobatics</Link> checks involving long jumps and high jumps; additionally, the wielder covers double the normal distance for a jump when making an Acrobatics check. The individual holding the rod also gain a +4 dodge bonus to AC when <Link to="/misc/fighting_defensively">fighting defensively</Link> instead of the usual +2 bonus. Also, while using this item, the user of the rod cannot be knocked <Link to="/rule/prone">prone</Link>, and takes only half damage from <Link to="/rule/falling">falling</Link>. A rod of balance emits a faint aura of the abjuration and transmutation schools.</p>
<h3 id="magic-rod-rod_of_balance-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/cats_grace">cat's grace</Link>, <Link to="/spell/feather_fall">feather fall</Link>, <Link to="/spell/jump">jump</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _rod_of_escape = {title: "Rod of Escape", jsx: <><h2 id="magic-rod-rod_of_escape-rod-of-escape">Rod of Escape</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 181</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>Wrought from <Link to="/eq-material/cold_iron">cold iron</Link>, this rod allows its wielder to escape from even the tightest of bonds or grasps. If an opponent <Link to="/rule/grapple">grapples</Link> the wielder of this rod, the ends of the rod extend, flailing about in an attempt to free the user. The rod's wielder gains a +5 bonus to CMD when attempting to evade or break out of a grapple; additionally, the holder cannot be pinned while wielding the rod.</p>
<p>The rod's wielder gains a +5 competence bonus on <Link to="/skill/escape_artist">Escape Artist</Link> checks when restrained by nonmagical and inanimate means, such as ropes or manacles. The rod's owner does not need to be holding the rod to gains this bonus; it must merely be on the owner's person.</p>
<h3 id="magic-rod-rod_of_escape-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/cats_grace">cat's grace</Link>, <Link to="/spell/shatter">shatter</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _rod_of_flame_extinguishing = {title: "Rod of Flame Extinguishing", jsx: <><h2 id="magic-rod-rod_of_flame_extinguishing-rod-of-flame-extinguishing">Rod of Flame Extinguishing</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 181</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 485</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 12th<br/><strong>Slot</strong> none; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This rod can extinguish Medium or smaller nonmagical fires with simply a touch (a standard action). For the rod to be effective against other sorts of fires, the wielder must expend 1 or more of the rod's charges.</p>
<p>Extinguishing a Large or larger nonmagical fire or a magic fire of size Medium or smaller (such as that of a flaming weapon or a burning hands spell), expends 1 charge. Continual magic flames, such as those generated by a weapon or a fire creature, are suppressed for 6 rounds and flare up again after that time. To extinguish an instantaneous fire spell, the rod must be within the area of the effect and the wielder must have used a <Link to="/rule/ready">ready</Link> action, effectively <Link to="/rule/counterspells">countering</Link> the entire spell.</p>
<p>When applied to Large or larger magic fires, such as those caused by <Link to="/spell/fireball">fireball</Link>, <Link to="/spell/flame_strike">flame strike</Link>, or <Link to="/spell/wall_of_fire">wall of fire</Link>, extinguishing the flames expends 2 charges from the rod.</p>
<p>If a rod of flame extinguishing is touched to a creature with the fire subtype by making a successful melee touch attack, the rod deals 6d6 points of damage to the creature. This use requires 3 charges.</p>
<p>A rod of flame extinguishing has 10 charges when found. Spent charges are renewed every day, so that a wielder can expend up to 10 charges in any 24-hour period.</p>
<h3 id="magic-rod-rod_of_flame_extinguishing-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/pyrotechnics">pyrotechnics</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _rod_of_gripping_smoke = {title: "Rod of Gripping Smoke", jsx: <><h2 id="magic-rod-rod_of_gripping_smoke-rod-of-gripping-smoke">Rod of Gripping Smoke</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_87_the_choking_tower">Pathfinder #87: The Choking Tower pg. 61</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 11th<br/><strong>Slot</strong> neck; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> 6 lbs.</p>
<p>One half of this rod is made of gray, semi-solid fog, while the other half glows from within as if filled with flickering embers. A rod of gripping smoke acts as a +1 <Link to="/magic-enh/ghost_touch">ghost touch</Link> <Link to="/eq-weapon/light_mace">light mace</Link>. Three times per day, as the wielder casts a spell that creates fog or smoke, it can make the effect particularly cloying, causing the area of the spell to count as <Link to="/rule/difficult_terrain">difficult terrain</Link>. This ability can't modify fog or smoke spells that already specifically impede movement (like <em>solid fog</em>).</p>
<p>Additionally, three times per day as a move action, the wielder of a rod of gripping smoke can point the rod at any single target within an area of fog, mist, smoke, or similar vapor within 60 feet (including the area of fog-like spells such as <Link to="/spell/cloudkill">cloudkill</Link> or <Link to="/spell/incendiary_cloud">incendiary cloud</Link>) and cause the vapor to tighten around that target. The wielder attempts a <Link to="/rule/disarm">disarm</Link>, <Link to="/rule/grapple">grapple</Link>, or <Link to="/rule/steal">steal</Link> combat maneuver at a +16 bonus against the target's CMD. This combat maneuver doesn't provoke an attack of opportunity. If the check to disarm succeeds, the disarmed weapon falls in a random square adjacent to the target. If the check to grapple succeeds, the target gains the <Link to="/rule/grappled">grappled</Link> condition for 1 round. While grappled in this way, the victim can't move without first breaking the grapple (CMD 26). If the check to steal succeeds, the stolen item lands in a random square adjacent to the target; unless the target succeeds at a DC 20 Perception check at the time the item is stolen, it doesn't realize the item is missing until it either leaves the affected area or attempts to use or retrieve the item.</p>
<h3 id="magic-rod-rod_of_gripping_smoke-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/solid_fog">solid fog</Link>, <Link to="/spell/telekinesis">telekinesis</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _rod_of_ruin = {title: "Rod of Ruin", jsx: <><h2 id="magic-rod-rod_of_ruin-rod-of-ruin">Rod of Ruin</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 183</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> none; <strong>Price</strong> 16,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This magical item appears to be an old and decaying scepter, with empty sockets for gemstones and rusted iron bands holding its rotting wooden shaft together. Three times per day on command, when the wielder touches the rod to a nonmagical, inanimate object, that object decays, cracks, and withers. The object, which can be no larger than a door or must take up no more than a 5-foot-by-5-foot area, gains the <Link to="/misc/broken">broken</Link> condition.</p>
<h3 id="magic-rod-rod_of_ruin-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/disintegrate">disintegrate</Link>; <strong>Cost</strong> 8,000 gp</p>
</>};
const _sapling_rod = {title: "Sapling Rod", jsx: <><h2 id="magic-rod-sapling_rod-sapling-rod">Sapling Rod</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 186</Link><br/><strong>Aura</strong> moderate conjuration and transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 16,650 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This rod appears to be the limbless trunk and branching roots of a miniature tree. It grants its wielder a +5 competence bonus on <Link to="/skill/survival">Survival</Link> checks to get along in the wild and to keep from getting lost. Additionally the wielder and any allies within a 20-foot radius of the wielder gain the benefits of the ranger's <Link to="/ability/woodland_stride">woodland stride</Link> class feature.</p>
<p>If thrust into any natural ground or earth and allowed to stand for 1 hour, the rod grows and blooms into a large tree bearing edible fruit. A sapling rod produces 2d4 pieces of fruit. A creature that consumes an entire piece of fruit gains the benefits of either a <em>cure moderate wounds</em> or <em>lesser restoration</em> spell (recipient's choice). Consuming a piece of fruit from a sapling rod is a full-round action that provokes attacks of opportunity, and no single creature can benefit from more than two piece of fruit from a single blooming. A sapling rod can bloom once per week and after doing so reverts to its original state after all the fruit is picked, or after 24 hours, whichever comes first. Fruit harvested from the tree lasts for 24 hours before shriveling into useless husks.</p>
<h3 id="magic-rod-sapling_rod-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/cure_moderate_wounds">cure moderate wounds</Link>, <Link to="/spell/grove_of_respite">grove of respite</Link>, <Link to="/spell/lesser_restoration">lesser restoration</Link>; <strong>Cost</strong> 8,325 gp</p>
</>};
const _scepter_of_divine_providence = {title: "Scepter of Divine Providence", jsx: <><h2 id="magic-rod-scepter_of_divine_providence-scepter-of-divine-providence">Scepter of Divine Providence</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_94_ice_tomb_of_the_giant_queen">Pathfinder #94: Ice Tomb of the Giant Queen pg. 38</Link><br/><strong>Aura</strong> strong (no school); <strong>CL</strong> 17th<br/><strong>Slot</strong> none; <strong>Price</strong> 17,312 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This iron rod is crowned with a metallic sphere and functions as a +1 <Link to="/eq-weapon/heavy_mace">heavy mace</Link>. In the hands of a divine spellcaster, the rod also counts as a holy or unholy symbol and divine focus. If the wielder of a scepter of divine providence has the <Link to="/ability/channel_energy">channel energy</Link> class feature, she can increase the radius of her channeled energy <Link to="/misc/burst">burst</Link> by 10 feet, at the cost of one additional use of her channel energy ability. The wielder can expend additional uses of her channel energy ability to further expand the burst radius, to a maximum of 30 additional feet.</p>
<h3 id="magic-rod-scepter_of_divine_providence-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/feat/widen_spell">Widen Spell</Link>, creator must have the channel energy class feature; <strong>Cost</strong> 8,812 gp</p>
</>};
const _rod_of_beguiling = {title: "Rod of Beguiling", jsx: <><h2 id="magic-rod-rod_of_beguiling-rod-of-beguiling">Rod of Beguiling</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 180</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 18,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This eye-catching rod is bedecked with glittering spangles. The wielder gains a +5 competence bonus on Bluff and <Link to="/skill/sleight_of_hand">Sleight of Hand</Link> checks, as well as on opposed Charisma checks to give commands to charmed creatures.</p>
<p>A rod of beguiling allows a bard's <Link to="/performance/fascinate">fascinate</Link>, <Link to="/performance/suggestion">suggestion</Link>, and <Link to="/performance/mass_suggestion">mass suggestion</Link> bardic performance to take effect as if she were 5 levels higher, and grants a +5 bonus on a bard's Perform checks when using <Link to="/performance/distraction">distraction</Link>.</p>
<h3 id="magic-rod-rod_of_beguiling-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/hypnotism">hypnotism</Link>; <strong>Cost</strong> 9,000 gp</p>
</>};
const _rod_of_nettles = {title: "Rod of Nettles", jsx: <><h2 id="magic-rod-rod_of_nettles-rod-of-nettles">Rod of Nettles</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 183</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> none; <strong>Price</strong> 18,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This wooden rod is engraved with serrated-edged leaves of stinging nettles. This rod acts as a +1 <Link to="/eq-weapon/light_mace">light mace</Link> that deals no damage. Instead, the rod's venomous touch (melee touch attack) deals 1d3 points of <Link to="/rule/dexterity_damage">Dexterity damage</Link> and causes the target to become <Link to="/misc/sickened">sickened</Link> for 1d6 rounds (DC 14 Fortitude negates the sickened effect and halves the Dexterity damage); on a critical hit, no saving throw is allowed.</p>
<p>Once per day on command, the wielder may touch the rod of nettles to ordinary vegetation, causing a 20-foot cube to become tangled with nettle - choked overgrowth as the overgrowth ability of the <em>plant growth</em> spell. Furthermore, creatures entering or within this area are affected as if touched by the rod, though creatures with a natural armor bonus of +3 or greater are immune to this effect. A creature that saves is unaffected by the area's poison for 24 hours.</p>
<h3 id="magic-rod-rod_of_nettles-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/plant_growth">plant growth</Link>, <Link to="/spell/poison">poison</Link>; <strong>Cost</strong> 9,000 gp</p>
</>};
const _rod_of_tangling_ectoplasm = {title: "Rod of Tangling Ectoplasm", jsx: <><h2 id="magic-rod-rod_of_tangling_ectoplasm-rod-of-tangling-ectoplasm">Rod of Tangling Ectoplasm</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 20</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 18,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This lengthy rod looks like a walking cane with a stylized crystal skull at its top. As a standard action up to three times per day, the wielder can slam the base of the rod into the ground while designating a target within 60 feet. Grasping hands of ectoplasm manifest from the ground surrounding the target in a 5-foot radius. Creatures within the radius must succeed at a DC 14 Reflex save or they are <Link to="/rule/entangled">entangled</Link> by the grasping hands and unable to move more than 10 feet from the affected area (as if snared by a <Link to="/eq-weapon/net">net</Link> with a trailing rope). Creatures moving through the ectoplasm must also succeed at a Reflex save or be entangled. As a standard action, a creature entangled by the ectoplasm can attempt an additional DC 14 Reflex save to attempt to escape and end the effect. The summoned ectoplasm lasts for 10 rounds before disappearing.</p>
<h3 id="magic-rod-rod_of_tangling_ectoplasm-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/ectoplasmic_snare">ectoplasmic snare</Link>; <strong>Cost</strong> 9,000 gp</p>
</>};
const _waterblight_scepter = {title: "Waterblight Scepter", jsx: <><h2 id="magic-rod-waterblight_scepter-waterblight-scepter">Waterblight Scepter</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 9</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 18,312 gp; <strong>Weight</strong> 8 lbs.</p>
<p>This gnarled blackwood scepter seeps tar, making it sticky to the touch. Around Cassomir, waterblight scepters are popular among inquisitors, oracles, and witches who regularly ply the Sellen River or the waters of the Inner Sea as members of merchant caravans, pirate crews, or pirate hunters.</p>
<p>The scepter acts as a +1 water-outsider-<Link to="/magic-enh/bane">bane</Link> <Link to="/eq-weapon/heavy_mace">heavy mace</Link>. When the scepter is wielded against creatures with the water subtype, damage dealt by the scepter also ignores 10 points of DR. Additionally, the wielder can use <em>water walk</em> once per day for 90 minutes. The duration of this ability need not be used all at once, but it must be used in 10-minute increments.</p>
<h3 id="magic-rod-waterblight_scepter-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/water_walk">water walk</Link>; <strong>Cost</strong> 13,312 gp</p>
</>};
const _rod_of_the_viper = {title: "Rod of the Viper", jsx: <><h2 id="magic-rod-rod_of_the_viper-rod-of-the-viper">Rod of the Viper</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 184</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 485</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 10th<br/><strong>Slot</strong> none; <strong>Price</strong> 19,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This rod strikes as a +2 <Link to="/eq-weapon/heavy_mace">heavy mace</Link>. Once per day, upon the wielder's command, the head of the rod becomes that of an actual serpent for 10 minutes. During this period, any successful strike with the rod deals its usual damage and also poisons the creature hit. This poison deals 1d3 points of <Link to="/rule/constitution_damage">Constitution damage</Link> per round for 6 rounds. Poisoned creatures can make a DC 16 Fortitude save each round to negate the damage and end the affliction. Multiple hits extend the duration by 3 rounds and increase the DC by 2 for each hit. The rod only functions if its possessor is evil.</p>
<h3 id="magic-rod-rod_of_the_viper-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/spell/poison">poison</Link>, creator must be evil; <strong>Cost</strong> 9,500 gp</p>
</>};
const _rod_of_minor_curses = {title: "Rod of Minor Curses", jsx: <><h2 id="magic-rod-rod_of_minor_curses-rod-of-minor-curses">Rod of Minor Curses</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 20</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> 4 lbs.</p>
<p>This rod functions as a +1 <Link to="/eq-weapon/light_mace">light mace</Link> and resembles the distorted femur of some monstrous creature. Up to three times per day when the wielder damages a creature with the rod, as a free action, the wielder can force the target to attempt a DC 14 Will save. On a failure, the creature suffers a minor curse. The wielder selects which of the following curses affects the target: -2 penalty to Strength (target's Strength cannot be reduced below 1); -1 penalty on attack rolls, saves, ability checks, and skill checks; or target has a 20% chance to begin each round with the <Link to="/misc/staggered">staggered</Link> condition. On a successful critical hit, the wielder can inflict two distinct curses if the target fails its save. Otherwise, a target can be subject to only one curse at a time.</p>
<p>Curses inflicted from the rod of minor curses last for 5 minutes. They can also be removed with any spell that can remove the effects of <em>bestow curse.</em></p>
<h3 id="magic-rod-rod_of_minor_curses-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/bestow_curse">bestow curse</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _rod_of_the_devoured_dawn = {title: "Rod of the Devoured Dawn", jsx: <><h2 id="magic-rod-rod_of_the_devoured_dawn-rod-of-the-devoured-dawn">Rod of the Devoured Dawn</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_83_the_slave_trenches_of_hakotep">Pathfinder #83: The Slave Trenches of Hakotep pg. 63</Link><br/><strong>Aura</strong> moderate illusion and transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> rod; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> 10 lbs.</p>
<p>The head of this rod is carved to resemble the visage of the Ancient Osirian deity <Link to="/faith/apep">Apep</Link>, Devourer of the Dawn, god of chaos, darkness, destruction, and snakes. A rod of the devoured dawn can be wielded as a +1 <Link to="/eq-weapon/heavy_mace">heavy mace</Link>. When holding the rod, the wielder gains darkvision with a range of 30 feet. Once per day, the rod can create a shadowy hypnotic pattern that also functions as <em>dispel magic</em> and targets any spells with the light descriptor in the area of effect.</p>
<p>When the wielder confirms a critical hit with a rod of the devoured dawn on a Medium or smaller foe, the head of the rod animates and grants an automatic <Link to="/rule/grapple">grapple</Link> check against the creature struck (this does not provoke an attack of opportunity). If the grapple check is successful, the rod's jaw unhinges and expands momentarily to swallow the creature, gulping it into a flesh-walled extradimensional space. The swallowed target gains the <Link to="/rule/grappled">grappled</Link> condition and takes 1d8 points of bludgeoning damage per round on its turn. The creature can cut its way out (AC 14, hp 24) or wriggle out with a successful DC 25 Escape Artist check as a full-round action - either method of escape causes the victim to be disgorged from the rod into an adjacent space. The rod automatically disgorges a swallowed victim if the swallowed creature dies or if the rod is destroyed. Only one creature can be swallowed at a time. A rod of the devoured dawn only functions if its wielder is chaotic.</p>
<h3 id="magic-rod-rod_of_the_devoured_dawn-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/darkvision">darkvision</Link>, <Link to="/spell/dispel_magic">dispel magic</Link>, <Link to="/spell/hypnotic_pattern">hypnotic pattern</Link>, <Link to="/spell/secret_chest">secret chest</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _suzerain_scepter = {title: "Suzerain Scepter", jsx: <><h2 id="magic-rod-suzerain_scepter-suzerain-scepter">Suzerain Scepter</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 186</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 7th<br/><strong>Slot</strong> none; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This ornately bejeweled baton confers the mark of rightful rulership on its bearer. The wielder of this scepter gains a +5 competence bonus on Knowledge (nobility) and Diplomacy checks. Furthermore, once per day, and on command, the wielder can affect up to seven living creatures with <em>good hope,</em> as the spell. If the wielder of a suzerain scepter has the <Link to="/feat/leadership">Leadership</Link> feat, she may attract double the normal number of followers for her Leadership score; however, if the rod is out of the wielder's possession for more than 1 week these extra followers leave. In addition, a suzerain scepter radiates a continuous <em>bless</em> effect that affects any cohort, follower, animal companion, familiar, special mount, or creature charmed or summoned by the wielder (but not called creatures or those under dominate or other compulsion effects). Whenever the wielder creates an effect that provides a morale bonus to such creatures (not including the scepter's <em>bless</em> effect), that bonus increases by 1.</p>
<h3 id="magic-rod-suzerain_scepter-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, Leadership, <Link to="/spell/bless">bless</Link>, <Link to="/spell/good_hope">good hope</Link>, <Link to="/spell/greater_command">greater command</Link>, the creator must have the Leadership feat; <strong>Cost</strong> 10,000 gp</p>
</>};
const _fiery_nimbus_rod = {title: "Fiery Nimbus Rod", jsx: <><h2 id="magic-rod-fiery_nimbus_rod-fiery-nimbus-rod">Fiery Nimbus Rod</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 178</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 6th<br/><strong>Slot</strong> none; <strong>Price</strong> 22,305 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This rod functions as a +1 <Link to="/magic-enh/flaming_burst">flaming burst</Link> <Link to="/eq-weapon/light_mace">light mace</Link>. Furthermore, when the rod confirms a critical hit, not only does it deal the extra damage from the flaming burst special ability, a nimbus of cold blue flames ignites the target for 1d4 rounds. This illuminates the target as the <em>faerie fire</em> spell. While the nimbus does not burn the target, it responds to melee attacks made against that foe. Each time an ignited foe takes damage from a melee attack, it takes and additional 1d10 fire damage.</p>
<p>Furthermore, once per day, as a free action, after hitting a foe with this rod, the wielder can surround the target of that attack with the nimbus, which has the same effect as the nimbus created by a confirmed critical hit.</p>
<h3 id="magic-rod-fiery_nimbus_rod-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/flame_blade">flame blade</Link>, <Link to="/spell/flame_strike">flame strike</Link> or <Link to="/spell/fireball">fireball</Link>, <Link to="/spell/faerie_fire">faerie fire</Link>; <strong>Cost</strong> 11,305 gp</p>
</>};
const _rod_of_enemy_detection = {title: "Rod of Enemy Detection", jsx: <><h2 id="magic-rod-rod_of_enemy_detection-rod-of-enemy-detection">Rod of Enemy Detection</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 181</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 485</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 10th<br/><strong>Slot</strong> none; <strong>Price</strong> 23,500 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This device pulses in the wielder's hand and points in the direction of any creature or creatures hostile to the bearer of the device (nearest ones first). These creatures can be invisible, ethereal, hidden, disguised, or in plain sight. The detection range is 60 feet. If the bearer of the rod concentrates for a full round, the rod pinpoints the location of the nearest enemy and indicates how many enemies are within range. The rod can be used to pinpoint enemies three times each day, each use lasting up to 10 minutes. Activating the rod is a standard action.</p>
<h3 id="magic-rod-rod_of_enemy_detection-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/true_seeing">true seeing</Link>; <strong>Cost</strong> 23,500 gp</p>
</>};
const _overflowing_rod = {title: "Overflowing Rod", jsx: <><h2 id="magic-rod-overflowing_rod-overflowing-rod">Overflowing Rod</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 254</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 10th<br/><strong>Slot</strong> none; <strong>Price</strong> 25,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>An overflowing rod amplifies and focuses the side effects of a <Link to="/class/kineticist">kineticist's</Link> burn. While holding the rod, the kineticist counts as 3 levels higher for the purpose of determining the effects of her elemental overflow ability. If used by a character without elemental overflow, the rod grants its wielder the benefit of elemental overflow as a 3rd-level kineticist (which is generally helpful only to low-level kineticists or kineticists with archetypes that replace elemental overflow with another class feature).</p>
<h3 id="magic-rod-overflowing_rod-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, creator must be a 10th-level kineticist; <strong>Cost</strong> 12,500 gp</p>
</>};
const _rod_of_perilous_pits = {title: "Rod of Perilous Pits", jsx: <><h2 id="magic-rod-rod_of_perilous_pits-rod-of-perilous-pits">Rod of Perilous Pits</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 14</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 25,000 gp; <strong>Weight</strong> 4 lbs.</p>
<p>This rod roughly resembles a torch with a small brass cage at the end. The wielder can cast any spell of 3rd level or lower into the rod. The rod can contain one spell at a time; casting a new spell into it replaces the older one. As long as a spell is contained within the rod, the brass cage glows as brightly as a <Link to="/eq-misc/candle">candle</Link>. The wielder of a rod of perilous pits can use the rod when casting a pit spell (<em>create pit,</em> <Link to="/spell/hungry_pit">hungry pit</Link>, and similar spells with "pit" in their names). Doing so changes that spell's casting time to a full-round action (or adds 1 round, if the casting time is already at least 1 full round). After successfully casting the <em>pit</em> spell, the rod's wielder can choose to manifest the contained spell inside the summoned pit. The contained spell manifests at the bottom of the pit, but does so after creatures have attempted their initial saves to avoid falling in. This allows the caster to center spells with a duration of instantaneous (such as <Link to="/spell/fireball">fireball</Link>) or spells with longer durations (such as <Link to="/spell/stinking_cloud">stinking cloud</Link>) within the pit.</p>
<h3 id="magic-rod-rod_of_perilous_pits-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/create_pit">create pit</Link>, creator must be a caster of at least 12th level; <strong>Cost</strong> 12,500 gp</p>
</>};
const _rod_of_splendor = {title: "Rod of Splendor", jsx: <><h2 id="magic-rod-rod_of_splendor-rod-of-splendor">Rod of Splendor</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 184</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 485</Link><br/><strong>Aura</strong> strong conjuration and transmutation; <strong>CL</strong> 12th<br/><strong>Slot</strong> none; <strong>Price</strong> 25,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>The possessor of this fantastically bejeweled rod gains a +4 enhancement bonus to her Charisma score for as long as she holds or carries the item. Once per day, the rod garbs her in magically created clothing of the finest fabrics, and adorns her with furs and jewels.</p>
<p>Apparel created by the magic of the rod remains in existence for 12 hours. However, if the possessor attempts to sell or give away any part of it, use it for a spell component, or the like, all the apparel immediately disappears. The same applies if any of it is forcibly taken from her.</p>
<p>The value of the noble garb created by the rod ranges from 7,000 to 10,000 gp (1d4+6 &times; 1,000 gp)-1,000 gp for the fabric alone, 5,000 gp for the furs, and the rest for the jewels (maximum of 20 gems; maximum value 200 gp each).</p>
<p>In addition, the rod has a second special power, usable once per week. Upon command, it creates a palatial tent - a huge pavilion of silk 60 feet across. Inside the tent are temporary furnishings and food suitable to the splendor of the pavilion and sufficient to entertain as many as 100 people. The tent and its trappings last for 1 day. At the end of that time, the tent and all objects associated with it (including any items that were taken out of the tent) disappear.</p>
<h3 id="magic-rod-rod_of_splendor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>, <Link to="/spell/fabricate">fabricate</Link>, <Link to="/spell/major_creation">major creation</Link>; <strong>Cost</strong> 12,500 gp</p>
</>};
const _rod_of_the_alicorn = {title: "Rod of the Alicorn", jsx: <><h2 id="magic-rod-rod_of_the_alicorn-rod-of-the-alicorn">Rod of the Alicorn</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 55</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 25,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This twisted wooden rod resembles the horn of a <Link to="/monster/unicorn">unicorn</Link>. Three times per day, the user can touch the rod to a target as a standard action and heal it with <em>cure light wounds.</em> Once per day, the user can heal a creature in this way with <em>cure moderate wounds.</em> Once per day, the user can also cast <em>neutralize poison</em> on a target in this way.</p>
<h3 id="magic-rod-rod_of_the_alicorn-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/cure_light_wounds">cure light wounds</Link>, <Link to="/spell/cure_moderate_wounds">cure moderate wounds</Link>, <Link to="/spell/neutralize_poison">neutralize poison</Link>, creator must be good-aligned; <strong>Cost</strong> 12,500 gp</p>
</>};
const _rod_of_withering = {title: "Rod of Withering", jsx: <><h2 id="magic-rod-rod_of_withering-rod-of-withering">Rod of Withering</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 185</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 485</Link><br/><strong>Aura</strong> strong necromancy; <strong>CL</strong> 13th<br/><strong>Slot</strong> none; <strong>Price</strong> 25,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>A rod of withering acts as a +1 <Link to="/eq-weapon/light_mace">light mace</Link> that deals no hit point damage. Instead, the wielder deals 1d4 points of <Link to="/rule/strength_damage">Strength damage</Link> and 1d4 points of Constitution damage to any creature she touches with the rod (by making a melee touch attack). If she scores a critical hit, the damage from that hit is permanent ability drain. In either case, the defender negates the effect with a DC 17 Fortitude save.</p>
<h3 id="magic-rod-rod_of_withering-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/contagion">contagion</Link>; <strong>Cost</strong> 12,500 gp</p>
</>};
const _rod_of_vicious_ghosts = {title: "Rod of Vicious Ghosts", jsx: <><h2 id="magic-rod-rod_of_vicious_ghosts-rod-of-vicious-ghosts">Rod of Vicious Ghosts</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 51</Link><br/><strong>Aura</strong> strong evocation; <strong>CL</strong> 13th<br/><strong>Slot</strong> none; <strong>Price</strong> 26,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Foreboding runes flow like shadows across the surface of this <Link to="/eq-material/mithral">mithral</Link> rod. Up to three times per day while on the Ethereal Plane, the wielder of this short rod can affect creatures on the Material Plane with spells and spell-like abilities with the force descriptor. After using this ability, the wielder glows faintly and can be seen by creatures on the Material Plane and the Ethereal Plane. This glowing effect lasts for 1 minute and is otherwise identical to <Link to="/spell/faerie_fire">faerie fire</Link>.</p>
<h3 id="magic-rod-rod_of_vicious_ghosts-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/ethereal_jaunt">ethereal jaunt</Link>; <strong>Cost</strong> 13,000 gp</p>
</>};
const _fossilizing_rod = {title: "Fossilizing Rod", jsx: <><h2 id="magic-rod-fossilizing_rod-fossilizing-rod">Fossilizing Rod</h2>
<p><strong>Sources</strong> <Link to="/source/elemental_masters_handbook">Elemental Master's Handbook pg. 10</Link><br/><strong>Aura</strong> moderate evocation and necromancy; <strong>CL</strong> 11th<br/><strong>Slot</strong> none; <strong>Price</strong> 26,400 gp; <strong>Weight</strong> 4 lbs.</p>
<p>This forearm-length rod of onyx gemstone is capped by a sphere of amber. Once per day when the bearer of a fossilizing rod casts <Link to="/spell/animate_dead">animate dead</Link> to animate skeletons, she can imbue the skeletons with fossilizing earth energy. Fossilized skeletons gain the earth subtype, reduce their Dexterity scores by 4 and their speeds by 10 feet, and cannot fly even if they could do so magically in life. However, due to the stone infusing their bones, fossilized skeletons gain hardness 8.</p>
<h3 id="magic-rod-fossilizing_rod-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/flesh_to_stone">flesh to stone</Link>; <strong>Cost</strong> 13,200 gp</p>
</>};
const _earthbind_rod = {title: "Earthbind Rod", jsx: <><h2 id="magic-rod-earthbind_rod-earthbind-rod">Earthbind Rod</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 178</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 148</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 6th<br/><strong>Slot</strong> none; <strong>Price</strong> 26,500 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This rod looks like nothing more than a large, strange sliver of rough granite. This rod's magic interacts with stone or earth to both steady its wielder and anchor creatures the rod touches. An earthbind rod functions like a +1 <Link to="/eq-weapon/light_mace">light mace</Link>, and it grants its wielder a +4 circumstance bonus to its CMD against <Link to="/rule/bull_rush">bull rush</Link>, <Link to="/rule/grapple">grapple</Link>, <Link to="/rule/overrun">overrun</Link>, <Link to="/rule/reposition">reposition</Link>, and <Link to="/rule/trip">trip</Link> combat maneuvers, but only if the wielder is an <Link to="/race/oread">oread</Link>, has the earth subtype, or is standing on earth or stone. Three times per day, when the wielder hits a creature with this rod, as long as the target of this attack is standing on stone or earth, the wielder can attempt to <Link to="/rule/entangled">entangle</Link> that creature (Fortitude DC 18 negates) for 1d4 rounds.</p>
<h3 id="magic-rod-earthbind_rod-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/stone_shape">stone shape</Link>; <strong>Cost</strong> 13,250 gp</p>
</>};
const _pyroclastic_spike = {title: "Pyroclastic Spike", jsx: <><h2 id="magic-rod-pyroclastic_spike-pyroclastic-spike">Pyroclastic Spike</h2>
<p><strong>Sources</strong> <Link to="/source/down_the_blighted_path">Down the Blighted Path pg. 62</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> none; <strong>Price</strong> 28,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This 3-foot-long, magically reinforced obsidian rod is capped with a globe of volcanic glass at one end, and a gleaming spike at the other. Veins of molten earth glow faintly beneath the rod's surface, flowing from a swirling fiery mass at the orb's core.</p>
<p>Once per day, the spiked end can be driven into sand, mud, or loose earth as a move action, into dense soil or loose gravel as a standard action, or into stone or metal as a full-round action. Once anchored, the earth in a path that is 5 feet wide and 30 feet long cracks and erupts with superheated gases in the direction of the wielder's choosing, originating in a square adjacent to the pyroclastic spike. Creatures standing in the path take 2d6 points of fire damage (Reflex DC 16 half) from the flaming jets of sulfuric gases as the ground beneath them begins to liquefy.</p>
<p>One round after anchoring the rod, liquid fire begins to pour from the pyroclastic spike along the affected area, creating a molten river 2 feet deep. The pyroclastic flow deals 10d6 points of fire damage to any barriers it encounters until it is able to flow freely forward to the full range of effect. Creatures in the area of effect automatically take 2d6 points of fire damage each round; those falling <Link to="/rule/prone">prone</Link> or held under the liquid fire take 10d6 points of fire damage each round. The molten river persists until the pyroclastic spike is removed from the ground as a full-round action, at which point the affected area immediately cools. Any creature in the molten terrain becomes <Link to="/rule/entangled">entangled</Link> when the rock cools, but may escape with a successful DC 16 Reflex save.</p>
<h3 id="magic-rod-pyroclastic_spike-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/firefall">firefall</Link>; <strong>Cost</strong> 14,000 gp</p>
</>};
const _rod_of_the_aboleth = {title: "Rod of the Aboleth", jsx: <><h2 id="magic-rod-rod_of_the_aboleth-rod-of-the-aboleth">Rod of the Aboleth</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 184</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> none; <strong>Price</strong> 29,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>The rod of the aboleth acts as a +1 <Link to="/magic-enh/corrosive">corrosive</Link> <Link to="/eq-weapon/light_mace">light mace</Link>. One end of the rod has three eye-shaped rubies imbedded in it, while the other end comes to a sharp point. When exposed to moisture, the surface of the rod takes on a slimy sheen that doesn't affect the wielder's grip. This rod has the following powers.</p>
<ul>
<li>Once per day as a free action, when the rod hits a living creature, the target must succeed at a DC 18 Fortitude saving throw or take 1d4 points of <Link to="/rule/constitution_damage">Constitution damage</Link>.</li>
<li>Once per day as a free action, when the rod hits a living creature, the creature must succeed at a DC 13 Will saving throw or be affected as though targeted with an <em>aboleth's lung</em> spell.</li>
<li>On command for 1 minute per day, the wielder may gain a swim speed of 60 feet for 1 minute. This time need not be continuous, and can be spent in 1-round increments.</li>
</ul>
<h3 id="magic-rod-rod_of_the_aboleth-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/aboleths_lung">aboleth's lung</Link>, <Link to="/spell/acid_arrow">acid arrow</Link>, <Link to="/spell/touch_of_the_sea">touch of the sea</Link>; <strong>Cost</strong> 29,000 gp</p>
</>};
const _liberators_rod = {title: "Liberator's Rod", jsx: <><h2 id="magic-rod-liberators_rod-liberators-rod">Liberator's Rod</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 179</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 30,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This bronze rod is capped with a hollow head formed by sweeping aquiline wings shielding a <em>continual flame.</em> A rod of liberty can be used as a +1 <Link to="/magic-enh/merciful">merciful</Link> <Link to="/eq-weapon/light_mace">light mace</Link>, but while its merciful property is suppressed by the wielder so is the <em>continual flame.</em> On command, the wielder of a rod of liberty may touch a creature that has failed a save against a charm, compulsion, or possession effect. Doing so grants that creature a new saving throw to end the effect. If this new save fails, the effect remains and the rod's touch cannot further affect it.</p>
<p>Once per day on command, the wielder can use <em>break enchantment,</em> as the spell.</p>
<h3 id="magic-rod-liberators_rod-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/break_enchantment">break enchantment</Link>, <Link to="/spell/cast_out">cast out</Link>, <Link to="/spell/continual_flame">continual flame</Link>; <strong>Cost</strong> 15,000 gp</p>
</>};
const _rod_of_hindered_healing = {title: "Rod of Hindered Healing", jsx: <><h2 id="magic-rod-rod_of_hindered_healing-rod-of-hindered-healing">Rod of Hindered Healing</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 14</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 7th<br/><strong>Slot</strong> none; <strong>Price</strong> 30,000 gp; <strong>Weight</strong> 4 lbs.</p>
<p>This black steel rod is capped by a circular pattern of pristine human finger bones. While held by a living creature, the rod radiates a moderate aura of negative energy that affects magical healing within a 60-foot radius of the wielder. Living creatures within this area must succeed at a DC 16 Will saving throw whenever they are subject to magic healing or receive only half the normal amount of healing.</p>
<h3 id="magic-rod-rod_of_hindered_healing-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/inflict_critical_wounds">inflict critical wounds</Link>; <strong>Cost</strong> 15,000 gp</p>
</>};
const _witching_rod = {title: "Witching Rod", jsx: <><h2 id="magic-rod-witching_rod-witching-rod">Witching Rod</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 254</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 11th<br/><strong>Slot</strong> none; <strong>Price</strong> 31,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This especially powerful <Link to="/eq-misc/dowsing_rod">dowsing rod</Link> is typically made of a branch from an ancient tree or shafts forged of rare metals. When used for the dowsing skill unlock in place of a mundane dowsing rod, a witching rod provides a +5 circumstance bonus on the <Link to="/skill/survival">Survival</Link> check.</p>
<p>A witching rod can not only detect bodies of water, grave sites, and metal deposits, but can also manipulate substances or souls related to them. The rod can produce the effects of <em>control water, speak with dead</em> (DC 14), or <em>stone shape.</em> Though this ability can typically be used only once per day, a wielder with the ability to use the dowsing occult skill unlock more than once per day can instead produce a spell effect one additional time per day for each additional use of dowsing she has. This doesn't require her to expend uses of dowsing. Only one creature can produce extra uses of the witching rod in this way each day.</p>
<h3 id="magic-rod-witching_rod-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/control_water">control water</Link>, <Link to="/spell/speak_with_dead">speak with dead</Link>, <Link to="/spell/stone_shape">stone shape</Link>; <strong>Cost</strong> 16,500 gp</p>
</>};
const _rod_of_voracious_hexes = {title: "Rod of Voracious Hexes", jsx: <><h2 id="magic-rod-rod_of_voracious_hexes-rod-of-voracious-hexes">Rod of Voracious Hexes</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 221</Link><br/><strong>Aura</strong> strong (no school); <strong>CL</strong> 17th<br/><strong>Slot</strong> none; <strong>Price</strong> 32,500 gp; <strong>Weight</strong> 5 lbs.</p>
<p>Three times per day when a wielder of this rod uses a hex (but not an advanced hex or grand hex), she can use this rod's power to target not only the hex's normal target, but also another target within 30 feet of the first. The hex must normally target a single creature within a range of at least 30 feet.</p>
<h3 id="magic-rod-rod_of_voracious_hexes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/feat/split_hex">Split Hex</Link>, creator must have the hex class feature; <strong>Cost</strong> 16,250 gp</p>
</>};
const _rod_of_thunder_and_lightning = {title: "Rod of Thunder and Lightning", jsx: <><h2 id="magic-rod-rod_of_thunder_and_lightning-rod-of-thunder-and-lightning">Rod of Thunder and Lightning</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 185</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 485</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 33,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>Constructed of iron set with silver rivets, this rod has the properties of a +2 <Link to="/eq-weapon/light_mace">light mace</Link>. Its other powers are as follows.</p>
<p><strong className="hl">Lightning:</strong> Once per day, when the wielder desires, a short spark of electricity can leap forth when the rod strikes an opponent to deal the normal damage for a +2 light mace (1d6+2) and an extra 2d6 points of electricity damage. Even when the rod fails to score a normal hit in combat, if the roll was good enough to count as a successful melee touch attack, then the 2d6 points of electricity damage still apply. The wielder activates this power as a free action, and it works if he strikes an opponent within 1 round.</p>
<p><strong className="hl">Lightning Stroke:</strong> Once per day as a standard action, the wielder can cause the rod to shoot out a 5-foot-wide <em>lightning bolt</em> dealing 9d6 points of electricity damage (Reflex DC 16 half) to a range of 200 feet.</p>
<p><strong className="hl">Thunder:</strong> Once per day, the rod can strike as a +3 light mace, and the opponent struck is <Link to="/misc/stunned">stunned</Link> from the noise of the rod's impact (Fortitude DC 16 negates). Activating this sonic power counts as a free action, and it works if the wielder strikes an opponent within 1 round.</p>
<p><strong className="hl">Thunderclap:</strong> Once per day as a standard action, the wielder can cause the rod to give out a deafening noise, just as a <em>shout</em> spell (Fortitude DC 16 partial, 2d6 points of sonic damage, target <Link to="/misc/deafened">deafened</Link> for 2d6 rounds).</p>
<p><strong className="hl">Thunder and Lightning:</strong> Once per week as a standard action, the wielder of the rod can combine the thunderclap power with a lightning bolt, as in the lightning stroke power. The thunderclap affects all creatures within 10 feet of the bolt. The lightning stroke deals 9d6 points of electricity damage (count rolls of 1 or 2 as rolls of 3, for a range of 27 to 54 points), and the thunderclap deals 2d6 points of sonic damage. A single DC 16 Reflex save applies for both effects.</p>
<h3 id="magic-rod-rod_of_thunder_and_lightning-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/lightning_bolt">lightning bolt</Link>, <Link to="/spell/shout">shout</Link>; <strong>Cost</strong> 16,500 gp</p>
</>};
const _booming_scepter = {title: "Booming Scepter", jsx: <><h2 id="magic-rod-booming_scepter-booming-scepter">Booming Scepter</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_high_court">Heroes of the High Court pg. 30</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 7th<br/><strong>Slot</strong> none; <strong>Price</strong> 34,000 gp; <strong>Weight</strong> 4 lbs.</p>
<p>This bejeweled scepter constantly emits a low hum that amplifies the wielder's voice. A booming scepter acts as a +1 <Link to="/magic-enh/thundering">thundering</Link> <Link to="/eq-weapon/light_mace">light mace</Link> that grants the wielder a +5 competence bonus on <Link to="/skill/intimidate">Intimidate</Link> checks and the ability to use <em>shout,</em> as per the spell, once per day. When a booming scepter is held in both hands, the wielder's voice carries far enough to be heard by all creatures within 1 mile, regardless of ambient noise or intervening obstacles, although this feature cannot penetrate the area of a <Link to="/spell/silence">silence</Link> spell.</p>
<h3 id="magic-rod-booming_scepter-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/shout">shout</Link>, <Link to="/spell/ventriloquism">ventriloquism</Link>; <strong>Cost</strong> 17,000 gp</p>
</>};
const _rod_of_delumination = {title: "Rod of Delumination", jsx: <><h2 id="magic-rod-rod_of_delumination-rod-of-delumination">Rod of Delumination</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 26</Link><br/><strong>Aura</strong> strong evocation; <strong>CL</strong> 17th<br/><strong>Slot</strong> none; <strong>Price</strong> 35,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This silvery rod is spoon-sized and utterly featureless. A creature holding a rod of delumination can extinguish any ability, item, or spell effect that is acting as a light source simply by pointing one end of the rod at the light and uttering a command word. Sources of magical light receive a DC 15 Will saving throw to negate this effect and have a Will save bonus equal to half their caster level; if the original caster of the effect is still within the spell's range, the spell can use its caster's Will save bonus instead. If a light source succeeds at its saving throw against a rod of delumination, the same rod cannot affect it again for 24 hours. No other properties of an affected creature, item, or spell are altered other than its ability to shed light; a <Link to="/eq-misc/torch">torch</Link> continues to burn, a <Link to="/eq-misc/lantern">lantern</Link> continues to consume oil, and so on.</p>
<p>The bearer can, if she chooses, utter a second command word to reignite any light source the rod has previously extinguished, provided that the light source's normal duration hasn't expired.</p>
<h3 id="magic-rod-rod_of_delumination-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/feat/snuffing_spell">Snuffing Spell</Link>; <strong>Cost</strong> 17,500 gp</p>
</>};
const _rod_of_negation = {title: "Rod of Negation", jsx: <><h2 id="magic-rod-rod_of_negation-rod-of-negation">Rod of Negation</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 183</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 485</Link><br/><strong>Aura</strong> strong varies; <strong>CL</strong> 15th<br/><strong>Slot</strong> none; <strong>Price</strong> 37,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This device negates the spell or spell-like function or functions of magic items. The wielder points the rod at the magic item, and a pale gray beam shoots forth to touch the target device, attacking as a ray (a ranged touch attack). The ray functions as a <Link to="/spell/greater_dispel_magic">greater dispel magic</Link> spell, except it only affects magic items. To negate instantaneous effects from an item, the rod's wielder needs to have a <Link to="/rule/readied_action">readied action</Link>. The dispel check uses the rod's caster level (15th). The target item gets no saving throw, although the rod can't negate <Link to="/rule/artifacts">artifacts</Link> (even minor artifacts). A rod of negation can function three times per day.</p>
<h3 id="magic-rod-rod_of_negation-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/dispel_magic">dispel magic</Link>, <Link to="/spell/limited_wish">limited wish</Link> or <Link to="/spell/miracle">miracle</Link>; <strong>Cost</strong> 18,500 gp</p>
</>};
const _rod_of_steadfast_resolve = {title: "Rod of Steadfast Resolve", jsx: <><h2 id="magic-rod-rod_of_steadfast_resolve-rod-of-steadfast-resolve">Rod of Steadfast Resolve</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 184</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 78</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 38,305 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This rod functions as a +2 <Link to="/eq-weapon/light_mace">light mace</Link>. It takes the form of a light mace with a head in the shape of a clenched fist. While a character wields this rod, it grants all his allies within a 20-foot-radius <Link to="/misc/burst">burst</Link> a +2 morale bonus on saving throws against fear and emotion effects, or a +4 morale bonus on such saves if the ally has the human subtype.</p>
<p>Also, once per day as an immediate action, the wielder can activate the rod to allow himself or a single ally within the rod's aura to reroll a failed saving throw against a spell or effect with the fear or emotion descriptor. The affected creature must take the result of the reroll, even if it is worse.</p>
<h3 id="magic-rod-rod_of_steadfast_resolve-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/bless">bless</Link>, <Link to="/spell/calm_emotions">calm emotions</Link>, creator must have the human subtype; <strong>Cost</strong> 19,305 gp</p>
</>};
const _ivory_baton = {title: "Ivory Baton", jsx: <><h2 id="magic-rod-ivory_baton-ivory-baton">Ivory Baton</h2>
<p><strong>Sources</strong> <Link to="/source/lost_kingdoms">Lost Kingdoms pg. 42</Link><br/><strong>Aura</strong> strong enchantment; <strong>CL</strong> 18th<br/><strong>Slot</strong> none; <strong>Price</strong> 40,000 gp; <strong>Weight</strong> 6 lbs.</p>
<p>This white, slender rod is engraved with decorative emblems of elephants, jackals, alligators, and other wild beasts, and is worth 2,000 gp because of its masterful craftsmanship. The wielder can command the obedience of <Link to="/family/golem">golems</Link> within 120 feet when she activates the device (a standard action), bypassing their immunity to magic and any other resistances to magic they may possess. Up to 300 Hit Dice worth of golems can be ruled at once with an ivory baton. Ruled golems obey the wielder as if she were their creator. Still, if the wielder attacks a ruled golem or gives it a command that is obviously harmful to it, the magic is broken. An ivory baton can be used for 500 total minutes before crumbling to dust. This duration need not be continuous. For each golem ruled beyond the first, multiply the number of minutes expended by the number of golems ruled (so, for example, a creature wielding an ivory baton to control three golems effectively expends 3 minutes of the rod's total duration every minute).</p>
<h3 id="magic-rod-ivory_baton-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/geas_quest">geas/quest</Link>, <Link to="/spell/mass_charm_monster">mass charm monster</Link>; <strong>Cost</strong> 21,000 gp</p>
</>};
const _coldwarp_key = {title: "Coldwarp Key", jsx: <><h2 id="magic-rod-coldwarp_key-coldwarp-key">Coldwarp Key</h2>
<p><strong>Sources</strong> <Link to="/source/magical_marketplace">Magical Marketplace pg. 29</Link><br/><strong>Aura</strong> moderate conjuration and transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 45,700 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This flanged iron rod is much heavier than it looks, and grants the wielder a portion of the skill of a master coldwarper.<sup><InnerLink showBacklink="backlink-magic-rod-coldwarp_key-ref-C-1" id="magic-rod-coldwarp_key-ref-C-1" data-hash-target to="magic-rod-coldwarp_key-C">1</InnerLink></sup> The wielder gains a +5 competence bonus on Craft checks involving metal.</p>
<p>A coldwarp key has three charges, which are renewed at midnight every night and can be expended to create a variety of effects. Expending one charge from a coldwarp key allows the wielder to use <em>fabricate</em> (as the spell) to affect metal only. If the wielder is in a natural underground environment, she can expend two charges from a coldwarp key to draw raw metal ore from the surrounding stone and shape it to her liking. This ability acts as the <em>major creation</em> spell, except the wielder can create only base metals and the duration is instantaneous.</p>
<h3 id="magic-rod-coldwarp_key-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/fabricate">fabricate</Link>, <Link to="/spell/major_creation">major creation</Link>; <strong>Cost</strong> 22,850 gp</p>
<section data-footnotes>
<h3 id="magic-rod-coldwarp_key-label">Footnotes</h3>
<ol>
<li id="magic-rod-coldwarp_key-C">
<p>Coldwarping is a Drow magical tradition that forges metal without need of fire. <InnerLink id="backlink-magic-rod-coldwarp_key-ref-C-1" data-hash-target to="magic-rod-coldwarp_key-ref-C-1" aria-label="Back to reference C-1">↩</InnerLink></p>
</li>
</ol>
</section>
</>};
const _fools_scepter = {title: "Fool's Scepter", jsx: <><h2 id="magic-rod-fools_scepter-fools-scepter">Fool's Scepter</h2>
<p><strong>Sources</strong> <Link to="/source/down_the_blighted_path">Down the Blighted Path pg. 61</Link><br/><strong>Aura</strong> strong divination and enchantment; <strong>CL</strong> 12th<br/><strong>Slot</strong> none; <strong>Price</strong> 50,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This wooden marotte is topped with a jester's head whose comical face takes on the likeness of the wielder. As a free action, the wielder of a fool's scepter can speak through the jester's head and imitate voices and sounds with a volume up to that of a dragon's roar. The wielder can also cause the jester's face to transform into the comic likeness of any creature she can visualize. Using a fool's scepter in this manner grants a +5 circumstance bonus to <Link to="/skill/perform">Perform (comedy)</Link> checks.</p>
<p>Once per day as a standard action, the wielder can cause the jester head to take on the likeness of an individual creature within 60 feet and then harangue that creature with magically honed mockery. If the creature possesses an Intelligence of 3 or higher, they are <Link to="/misc/dazed">dazed</Link> with humiliation for 2d6 rounds and <Link to="/misc/shaken">shaken</Link> for 10 minutes. This is a mind-affecting, language-dependent compulsion effect, and is negated by a successful DC 15 Will saving throw.</p>
<p>Once per week as a standard action, the wielder can query the jester's head for information regarding an individual creature. The head transforms into the likeness of that creature and recites a number of jocular stories over the next 2d6 &times; 10 minutes, providing information as per the <em>legend lore</em> spell. If the subject of the wielder's query is present and within 60 feet, the head also provides information regarding the subject's thoughts, desires, personality, and motivations as if using <Link to="/spell/detect_thoughts">detect thoughts</Link>, though the subject may negate this divination with a successful DC 15 Will save. In this circumstance, the head always answers in a voice that is loud enough to be audible to the subject of the query.</p>
<h3 id="magic-rod-fools_scepter-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/ghost_sound">ghost sound</Link>, <Link to="/spell/hideous_laughter">hideous laughter</Link>, <Link to="/spell/legend_lore">legend lore</Link>; <strong>Cost</strong> 25,000 gp</p>
</>};
const _forked_rod = {title: "Forked Rod", jsx: <><h2 id="magic-rod-forked_rod-forked-rod">Forked Rod</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 51</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 50,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This bifurcated mithral rod resembles an oversized tuning fork. The forked rod acts as a focus for <em>plane shift,</em> but the plane to which it is attuned to can be adjusted as a standard action - a forked rod can be attuned to any plane that a common tuning fork (see <em>plane shift</em>) can be attuned to. Once per day, a forked rod can be used to cast <em>plane shift</em> to the plane it is currently attuned to. Three times per day as a standard action, the user can attack a creature or object with a forked rod as if it were a +1 <Link to="/eq-weapon/light_mace">light mace</Link>. On a hit, the forked rod deals no damage, but affects the target with <em>dimensional anchor</em> for 9 minutes. As long as a target is affected in this way, the forked rod is inert and cannot be used to cast <em>plane shift,</em> as a focus for <em>plane shift,</em> or to affect another target with <em>dimensional anchor.</em></p>
<h3 id="magic-rod-forked_rod-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/dimensional_anchor">dimensional anchor</Link>, <Link to="/spell/plane_shift">plane shift</Link>; <strong>Cost</strong> 25,000 gp</p>
</>};
const _rod_of_absorption = {title: "Rod of Absorption", jsx: <><h2 id="magic-rod-rod_of_absorption-rod-of-absorption">Rod of Absorption</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 179</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 485</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 15th<br/><strong>Slot</strong> none; <strong>Price</strong> 50,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This rod absorbs spells or spell-like abilities into itself. The magic absorbed must be a single-target spell or a ray directed at either the character holding the rod or her gear. The rod then nullifies the spell's effect and stores its potential until the wielder releases this energy in the form of spells of her own. She can instantly detect a spell's level as the rod absorbs that spell's energy. Absorption requires no action on the part of the user if the rod is in hand at the time.</p>
<p>A running total of absorbed (and used) spell levels should be kept. The wielder of the rod can use captured spell energy to cast any spell she has prepared without expending the prepared spell itself. The only restrictions are that the levels of spell energy stored in the rod must be equal to or greater than the level of the spell the wielder wants to cast, that any material components required for the spell be present, and that the rod be in the wielder's hand when he casts the spell. For casters such as bards or sorcerers who do not prepare spells, the rod's energy can be used to cast any spell of the appropriate level or levels that they know.</p>
<p>A rod of absorption can absorb a maximum of 50 spell levels and thereafter can only discharge any remaining potential it might have. The rod cannot be recharged. The wielder knows the rod's remaining absorbing potential and current amount of stored energy.</p>
<p>To determine the absorption potential remaining in a newly found rod, roll d% and divide the result by 2. Then roll d% again: on a result of 71-100, half the levels already absorbed by the rod are still stored within.</p>
<h3 id="magic-rod-rod_of_absorption-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/spell_turning">spell turning</Link>; <strong>Cost</strong> 25,000 gp</p>
</>};
const _rod_of_flailing = {title: "Rod of Flailing", jsx: <><h2 id="magic-rod-rod_of_flailing-rod-of-flailing">Rod of Flailing</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 181</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 485</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 50,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>Upon the command of its possessor, this rod activates, changing from a normal-seeming rod to a +3/+3 <Link to="/eq-weapon/dire_flail">dire flail</Link>. The dire flail is a <Link to="/misc/double">double</Link> weapon, which means that each of the weapon's heads can be used to attack. The wielder can gain an extra attack (with the second head) at the cost of making all attacks at a -2 penalty (as if she had the <Link to="/feat/two_weapon_fighting">Two-Weapon Fighting</Link> feat).</p>
<p>Once per day, the wielder can use a free action to cause the rod to grant her a +4 deflection bonus to AC and a +4 resistance bonus on saving throws for 10 minutes. The rod need not be in weapon form to grant this benefit.</p>
<p>Transforming a rod of flailing into a weapon or back into a rod is a move action.</p>
<h3 id="magic-rod-rod_of_flailing-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/bless">bless</Link>; <strong>Cost</strong> 25,000 gp</p>
</>};
const _rod_of_potent_hexes = {title: "Rod of Potent Hexes", jsx: <><h2 id="magic-rod-rod_of_potent_hexes-rod-of-potent-hexes">Rod of Potent Hexes</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 220</Link><br/><strong>Aura</strong> strong (no school); <strong>CL</strong> 17th<br/><strong>Slot</strong> none; <strong>Price</strong> 54,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>Three times per day when a wielder of this rod uses a hex (but not an advanced hex or grand hex), she can use this rod's power to double the damage dealt or healed by the hex. To be augmented in this way, a hex must directly heal damage, directly deal damage, or grant a creature some form of attack or aura that deals damage.</p>
<h3 id="magic-rod-rod_of_potent_hexes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/feat/maximize_spell">Maximize Spell</Link>, creator must possess the hex class feature; <strong>Cost</strong> 27,000 gp</p>
</>};
const _gravitic_force_rod = {title: "Gravitic Force Rod", jsx: <><h2 id="magic-rod-gravitic_force_rod-gravitic-force-rod">Gravitic Force Rod</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 13</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 15th<br/><strong>Slot</strong> none; <strong>Price</strong> 60,000 gp; <strong>Weight</strong> 4 lbs.</p>
<p>This heavy leaden rod is carved with a series of glyphs that resemble Terran writing. It has a single activation stud at its base. A creature can activate the rod by pressing the stud or by placing the rod on the ground. Once activated, the rod creates a field of intensified gravity within a 100-foot radius. Creatures within the area weigh twice as much as normal, can move only at half speed, can jump only half as far as normal, and can lift and carry only half as much as normal. Any flying target has its maneuverability worsened by two steps (from good to poor, for example; minimum clumsy) and plummets to the ground unless it succeeds at a DC 25 <Link to="/skill/fly">Fly</Link> check.</p>
<h3 id="magic-rod-gravitic_force_rod-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/reverse_gravity">reverse gravity</Link>; <strong>Cost</strong> 30,000 gp</p>
</>};
const _rod_of_rulership = {title: "Rod of Rulership", jsx: <><h2 id="magic-rod-rod_of_rulership-rod-of-rulership">Rod of Rulership</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 183</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 485</Link><br/><strong>Aura</strong> strong enchantment; <strong>CL</strong> 20th<br/><strong>Slot</strong> none; <strong>Price</strong> 60,000 gp; <strong>Weight</strong> 8 lbs.</p>
<p>This rod looks like a royal scepter worth at least 5,000 gp in materials and workmanship alone. The wielder can command the obedience and fealty of creatures within 120 feet when she activates the device (a standard action). Creatures totaling 300 Hit Dice can be ruled, but creatures with Intelligence scores of 12 or higher are each entitled to a DC 16 Will save to negate the effect. Ruled creatures obey the wielder as if she were their absolute sovereign. Still, if the wielder gives a command that is contrary to the nature of the creatures commanded, the magic is broken. The rod can be used for 500 total minutes before it crumbles to dust. This duration need not be continuous.</p>
<h3 id="magic-rod-rod_of_rulership-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/mass_charm_monster">mass charm monster</Link>; <strong>Cost</strong> 32,500 gp</p>
</>};
const _rod_of_security = {title: "Rod of Security", jsx: <><h2 id="magic-rod-rod_of_security-rod-of-security">Rod of Security</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 183</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 485</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 20th<br/><strong>Slot</strong> none; <strong>Price</strong> 61,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This item creates a non-dimensional space, a pocket paradise. There the rod's possessor and as many as 199 other creatures can stay in complete safety for a period of time - up to 200 days divided by the number of creatures affected. All fractions are rounded down. In this pocket paradise, creatures don't age, and natural healing takes place at twice the normal rate. Fresh water and food (fruits and vegetables only) are abundant. The climate is comfortable for all creatures present. Activating the rod (a standard action) causes the wielder and all creatures touching the rod to be transported instantaneously to the paradise. Members of large groups can hold hands or otherwise maintain physical contact, allowing all connected creatures in a circle or a chain to be affected by the rod. Unwilling creatures get a DC 17 Will save to negate the effect. If an unwilling creature succeeds at its save, other creatures beyond that point in a chain can still be affected by the rod.</p>
<p>When the rod's effect expires, is <Link to="/misc/dismiss">dismissed</Link>, or is <Link to="/spell/dispel">dispelled</Link>, all the affected creatures instantly reappear in the location they occupied when the rod was activated. If something else occupies the space that a traveler would be returning to, then his body is displaced a sufficient distance to provide the space required for reentry. The rod's possessor can dismiss the effect whenever he wishes before the maximum time period expires, but the rod can only be activated once per week.</p>
<h3 id="magic-rod-rod_of_security-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/gate">gate</Link>; <strong>Cost</strong> 30,500 gp</p>
</>};
const _rod_of_well_deserved_rest = {title: "Rod of Well-Deserved Rest", jsx: <><h2 id="magic-rod-rod_of_well_deserved_rest-rod-of-well-deserved-rest">Rod of Well-Deserved Rest</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_39_the_city_of_seven_spears">Pathfinder #39: The City of Seven Spears pg. 56</Link><br/><strong>Aura</strong> strong enchantment and evocation; <strong>CL</strong> 12th<br/><strong>Slot</strong> none; <strong>Price</strong> 62,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This rod is made of polished gold, and features three blown-glass onion domes at one end. It functions as a +1 <Link to="/eq-weapon/light_mace">light mace</Link>. Up to three times per day, with a successful hit in combat, the wearer may attempt to put the target of the attack asleep (DC 14 Will save negates). This functions as <Link to="/spell/sleep">sleep</Link>, but there is no limit to the number of Hit Dice that may be affected.</p>
<p>In addition, the wielder may create an opaque sphere of force to protect himself from the elements once per day, as a <em>tiny hut</em> spell with a 5-foot radius. If the wielder goes to sleep with the rod in his possession, 8 hours of sleep provides <Link to="/rule/healing">healing</Link> equivalent to a full day of bed rest. Upon waking, the wielder enjoys the benefits of a <em>good hope</em> spell for 1 hour.</p>
<h3 id="magic-rod-rod_of_well_deserved_rest-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/deep_slumber">deep slumber</Link>, <Link to="/spell/good_hope">good hope</Link>, <Link to="/spell/restful_sleep">restful sleep</Link>, <Link to="/spell/tiny_hut">tiny hut</Link>; <strong>Cost</strong> 31,000 gp</p>
</>};
const _rod_of_shadows = {title: "Rod of Shadows", jsx: <><h2 id="magic-rod-rod_of_shadows-rod-of-shadows">Rod of Shadows</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 184</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 106</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 8th<br/><strong>Slot</strong> none; <strong>Price</strong> 64,305 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This ebon rod is so dark it seems to absorb the light around it. The rod functions as a +2 <Link to="/eq-weapon/light_mace">light mace</Link>, and allows its wielder to see in darkness as if she had the <Link to="/umr/see_in_darkness">see in darkness</Link> ability. Three times per day, the wielder can use it to create a <em>deeper darkness</em> effect (caster level 8th). To use this ability, the rod's wielder must touch the target object, which is a standard action that provokes attacks of opportunity.</p>
<h3 id="magic-rod-rod_of_shadows-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/deeper_darkness">deeper darkness</Link>, <Link to="/spell/true_seeing">true seeing</Link>; <strong>Cost</strong> 32,305 gp</p>
</>};
const _rod_of_razors = {title: "Rod of Razors", jsx: <><h2 id="magic-rod-rod_of_razors-rod-of-razors">Rod of Razors</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_35_war_of_the_river_kings">Pathfinder #35: War of the River Kings pg. 46</Link><br/><strong>Aura</strong> n/a (see source); <strong>CL</strong> 15th<br/><strong>Slot</strong> none; <strong>Price</strong> 65,000 gp; <strong>Weight</strong> 10 lbs.</p>
<p>This ornate, <Link to="/eq-material/adamantine">adamantine</Link> rod appears to be a cross between a <Link to="/eq-weapon/halberd">halberd</Link> and a strange scepter of alien design. Despite its rigid appearance, the rod is surprisingly flexible and can extend in combat - the weapon functions as a +3 <Link to="/magic-enh/keen">keen</Link> adamantine halberd that has <Link to="/misc/reach">reach</Link> but can still function normally against adjacent foes. As a full-round action up to five times per day, the rod can be used to fire razors. Treat these as +3 keen adamantine arrows fired from a <Link to="/eq-weapon/longbow">longbow</Link> (any feats possessed by the user that function with longbows work with these flechettes).</p>
<h3 id="magic-rod-rod_of_razors-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/blade_barrier">blade barrier</Link>, <Link to="/spell/keen_edge">keen edge</Link>, <Link to="/spell/shield">shield</Link>, <Link to="/spell/spiritual_weapon">spiritual weapon</Link>; <strong>Cost</strong> 33,435 gp</p>
</>};
const _rod_of_mind_mastery = {title: "Rod of Mind Mastery", jsx: <><h2 id="magic-rod-rod_of_mind_mastery-rod-of-mind-mastery">Rod of Mind Mastery</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 182</Link><br/><strong>Aura</strong> moderate abjuration and divination; <strong>CL</strong> 7th<br/><strong>Slot</strong> none; <strong>Price</strong> 67,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This rod is a simple, unadorned piece of clear crystal that has been magically hardened. The wielder of the rod is under a constant <em>nondetection</em> effect, as the spell. Furthermore, the rod has the following powers.</p>
<ul>
<li>Three times per day on command, the user of the rod can use it to <em>detect thoughts</em> as the spell.</li>
<li>Once per day as an immediate action, the wielder may determine whether someone is lying to her, as the <em>discern lies</em> spell.</li>
</ul>
<h3 id="magic-rod-rod_of_mind_mastery-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/detect_thoughts">detect thoughts</Link>, <Link to="/spell/discern_lies">discern lies</Link>, <Link to="/spell/nondetection">nondetection</Link>; <strong>Cost</strong> 33,500 gp</p>
</>};
const _rod_of_lordly_might = {title: "Rod of Lordly Might", jsx: <><h2 id="magic-rod-rod_of_lordly_might-rod-of-lordly-might">Rod of Lordly Might</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 182</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 485</Link><br/><strong>Aura</strong> strong varies; <strong>CL</strong> 19th<br/><strong>Slot</strong> none; <strong>Price</strong> 70,000 gp; <strong>Weight</strong> 10 lbs.</p>
<p>This rod has functions that are spell-like, and it can also be used as a magic weapon of various sorts. In addition, it has several more mundane uses. The rod of lordly might is metal and thicker than other rods, with a flanged ball at one end and six stud-like buttons along its length. Pushing any of the rod's buttons is an action equivalent to drawing a weapon, and the rod weighs 10 pounds.</p>
<p>The following spell-like functions of the rod can each be used once per day.</p>
<ul>
<li>Use <em>hold person</em> upon a touched creature, if the wielder so commands (Will DC 14 negates). The wielder must choose to use this power (a free action) and then succeed at a melee touch attack to activate the power. If the attack fails, the effect is lost.</li>
<li>Use <em>fear</em> upon all enemies viewing it, if the wielder so desires (10-foot maximum range, Will DC 16 partial). Invoking this power is a standard action.</li>
<li>Deal 2d4 hit points of damage to an opponent on a successful touch attack (Will DC 17 half) and cure the wielder of the same amount of damage. The wielder must choose to use this power before attacking, as with <em>hold person.</em></li>
</ul>
<p>The following functions of the rod have no limit on the number of times they can be employed.</p>
<ul>
<li>In its normal form, the rod can be used as a +2 <Link to="/eq-weapon/light_mace">light mace</Link>.</li>
<li>When button 1 is pushed, the rod becomes a +1 <Link to="/magic-enh/flaming">flaming</Link> <Link to="/eq-weapon/longsword">longsword</Link>. A blade springs from the ball, with the ball itself becoming the sword's hilt. The weapon stretches to an overall length of 4 feet.</li>
<li>When button 2 is pushed, the rod becomes a +4 <Link to="/eq-weapon/battleaxe">battleaxe</Link>. A wide blade springs forth from the ball, and the whole weapon lengthens to 4 feet.</li>
<li>When button 3 is pushed, the rod becomes a +3 <Link to="/eq-weapon/shortspear">shortspear</Link> or a +3 <Link to="/eq-weapon/longspear">longspear</Link>. A spear blade springs forth, and the handle can be lengthened up to 12 feet (wielder's choice) for an overall length ranging from 6 feet to 15 feet. At its 15-foot length, the rod is suitable for use as a <Link to="/eq-weapon/lance">lance</Link>.</li>
</ul>
<p>The following other functions of the rod also have no limit on the number of times they can be employed.</p>
<ul>
<li>When button 4 is pushed, a spike that can anchor in stone is extruded from the ball, while the other end sprouts three sharp hooks. The rod lengthens to anywhere between 5 and 50 feet in a single round, stopping when button 4 is pushed again. Horizontal bars 3 inches long fold out from the sides, 1 foot apart, in a staggered progression. The rod is firmly held by the spike and hooks and can bear up to 4,000 pounds. The wielder can retract the climbing pole by pushing button 5.</li>
<li>The ladder function can be used to force open doors. The wielder plants the rod's base 30 feet or less from the portal to be forced and in line with it, then pushes button 4. The force exerted has a Strength modifier of +12.</li>
<li>When button 6 is pushed, the rod indicates magnetic north and gives the wielder knowledge of his approximate depth beneath the surface or height above it.</li>
</ul>
<h3 id="magic-rod-rod_of_lordly_might-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/fear">fear</Link>, <Link to="/spell/flame_blade">flame blade</Link>, <Link to="/spell/hold_person">hold person</Link>, <Link to="/spell/inflict_light_wounds">inflict light wounds</Link>; <strong>Cost</strong> 35,000 gp</p>
</>};
const _scepter_of_heaven = {title: "Scepter of Heaven", jsx: <><h2 id="magic-rod-scepter_of_heaven-scepter-of-heaven">Scepter of Heaven</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 186</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 10th<br/><strong>Slot</strong> none; <strong>Price</strong> 74,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This ornate scepter of bronze and mithral has a flanged head like a golden-white sunburst. A scepter of heaven acts as a +1 evil outsider <Link to="/magic-enh/bane">bane</Link> <Link to="/eq-weapon/morningstar">morningstar</Link>. The scepter has the following powers when wielded by a good-aligned creature.</p>
<ul>
<li>The wielder of a scepter of heaven gains a +2 sacred bonus on caster level checks made to <Link to="/spell/dispel_magic">dispel magic</Link> against with the evil descriptor or effects created by evil outsiders.</li>
<li>The wielder can use the scepter to use <em>bless weapon</em> on command and at will as the spell.</li>
<li>Once per day on command, if the wielder can shoot a <em>spear of purity</em> from the scepter.</li>
</ul>
<p>If the wielder of a scepter of heaven wears a <Link to="/magic-wondrous/crown_of_heaven">crown of heaven</Link>, the scepter's caster level increases to 15th (increasing its aura to strong) and, when used as a weapon, it gains the <Link to="/magic-enh/holy">holy</Link> property. A good-aligned wielder may also use <em>holy smite, holy sword,</em> and <em>holy word,</em> as the spells, once per day each.</p>
<p>A scepter of heaven is of good alignment, and any evil creature attempting to wield one gains one <Link to="/rule/negative_level">negative level</Link>. The negative level remains as long as the rod is in hand and disappears when the rod is no longer held. This negative level cannot be overcome in any way (including <Link to="/spell/restoration">restoration</Link> spells) while the rod is being held.</p>
<h3 id="magic-rod-scepter_of_heaven-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/bless_weapon">bless weapon</Link>, <Link to="/spell/dispel_evil">dispel evil</Link>, <Link to="/spell/holy_smite">holy smite</Link>, <Link to="/spell/holy_sword">holy sword</Link>, <Link to="/spell/holy_word">holy word</Link>, <Link to="/spell/spear_of_purity">spear of purity</Link>, creator must be good; <strong>Cost</strong> 37,000 gp</p>
</>};
const _rod_of_abrupt_hexes = {title: "Rod of Abrupt Hexes", jsx: <><h2 id="magic-rod-rod_of_abrupt_hexes-rod-of-abrupt-hexes">Rod of Abrupt Hexes</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 220</Link><br/><strong>Aura</strong> strong (no school); <strong>CL</strong> 17th<br/><strong>Slot</strong> none; <strong>Price</strong> 75,500 gp; <strong>Weight</strong> 5 lbs.</p>
<p>Three times per day when a wielder of this rod uses a hex (but not an advanced hex or grand hex), she can use this rod's power to activate the hex as swift action rather than a standard action.</p>
<h3 id="magic-rod-rod_of_abrupt_hexes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/feat/quicken_spell">Quicken Spell</Link>, creator must possess the hex class feature; <strong>Cost</strong> 37,750 gp</p>
</>};
const _lava_rod = {title: "Lava Rod", jsx: <><h2 id="magic-rod-lava_rod-lava-rod">Lava Rod</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_95_anvil_of_fire">Pathfinder #95: Anvil of Fire pg. 32</Link><br/><strong>Aura</strong> strong evocation [fire]; <strong>CL</strong> 13th<br/><strong>Slot</strong> none; <strong>Price</strong> 80,000 gp; <strong>Weight</strong> 8 lbs.</p>
<p>This irregularly shaped iron rod is studded with orange gems. It can be wielded as a +2 <Link to="/eq-weapon/club">club</Link>. For 10 rounds per day, the rod can be wielded as a +2 <Link to="/magic-enh/flaming_burst">flaming burst</Link> club. These rounds need not be consecutive. Additionally, three times per day as a standard action, a creature wielding this rod can use it to spray a 30-foot cone of lava droplets that deals 13d6 points of fire damage (Reflex DC 20 half). Once per day as a standard action, the wielder can instead release a cone of harmless pebbles that fall to the ground and cover the area. These pebbles transform into tiny blobs of lava up to 5 rounds later. The user determines the round upon which the pebbles transform into lava when initially activating the rod for this effect. Any creature in the area of the pebbles when they transform takes 13d6 points of fire damage (Reflex DC 20 half).</p>
<h3 id="magic-rod-lava_rod-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/delayed_blast_fireball">delayed blast fireball</Link>; <strong>Cost</strong> 40,000 gp</p>
</>};
const _nightmare_rod = {title: "Nightmare Rod", jsx: <><h2 id="magic-rod-nightmare_rod-nightmare-rod">Nightmare Rod</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_65_into_the_nightmare_rift">Pathfinder #65: Into the Nightmare Rift pg. 63</Link><br/><strong>Aura</strong> strong illusion; <strong>CL</strong> 13th<br/><strong>Slot</strong> none; <strong>Price</strong> 80,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>A nightmare rod is a wooden rod with a smooth, purple, crystalline octopus clutching one end, its tentacles wrapped around the length of the rod and its bulbous body serving as a sort of mace head. Indeed, a nightmare rod can be wielded as a +2 <Link to="/eq-weapon/heavy_mace">heavy mace</Link>. On a critical hit, a nightmare rod floods the target's mind with horrific visions of nightmarish dooms that <Link to="/misc/staggered">stagger</Link> the victim for 1 round if it fails a DC 15 Will save. This is a mind-affecting fear effect. In addition, a nightmare rod has the following powers.</p>
<ul>
<li>Once per day as a free action when the rod hits a living creature, the user can affect the creature struck with a <em>phantasmal killer</em> spell (Will/Fort DC 16).</li>
<li>Once per day, the user can cast <em>nightmare.</em> If the recipient is awake when the spell begins, the wielder need not enter a trance (as he would if he had cast the spell) - the nightmare rod maintains its own sort of trance on the spell and automatically finishes casting the spell as soon as the recipient falls asleep. If the recipient does not fall asleep within 24 hours, the nightmare rod ceases attempting to cast the spell automatically.</li>
<li>As long as the wielder carries the nightmare rod in his hand, he is immune to fear effects.</li>
</ul>
<h3 id="magic-rod-nightmare_rod-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/fear">fear</Link>, <Link to="/spell/nightmare">nightmare</Link>, <Link to="/spell/phantasmal_killer">phantasmal killer</Link>, <Link to="/spell/remove_fear">remove fear</Link>; <strong>Cost</strong> 40,000 gp</p>
</>};
const _rod_of_dwarven_might = {title: "Rod of Dwarven Might", jsx: <><h2 id="magic-rod-rod_of_dwarven_might-rod-of-dwarven-might">Rod of Dwarven Might</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 181</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 19</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 19th<br/><strong>Slot</strong> none; <strong>Price</strong> 80,000 gp; <strong>Weight</strong> 10 lbs.</p>
<p>This dwarven version of the more famous <Link to="/magic-rod/rod_of_lordly_might">rod of lordly might</Link> has no spell-like powers; however, when wielded by a <Link to="/race/dwarf">dwarf</Link>, it increases all AC, attack roll, CMD, CMB, and saving throw bonuses from a dwarf's racial traits by +1. The rod shares the mundane powers of a rod of lordly might, but its magical weapon forms are tailored to dwarven preferences.</p>
<ul>
<li>In its normal form, the rod can be used as a +1 <Link to="/magic-enh/returning">returning</Link> <Link to="/eq-weapon/light_hammer">light hammer</Link>.</li>
<li>When button 1 is pushed, the rod becomes a +3 <Link to="/eq-weapon/dwarven_longhammer">dwarven longhammer</Link>.</li>
<li>When button 2 is pushed, the rod becomes a +4 <Link to="/eq-weapon/dwarven_waraxe">dwarven waraxe</Link>.</li>
<li>When button 3 is pushed, the rod becomes a +2 <Link to="/eq-weapon/light_crossbow">light crossbow</Link> or +2 <Link to="/eq-weapon/heavy_crossbow">heavy crossbow</Link>.</li>
</ul>
<h3 id="magic-rod-rod_of_dwarven_might-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>; <strong>Cost</strong> 40,000 gp</p>
</>};
const _rod_of_revolution = {title: "Rod of Revolution", jsx: <><h2 id="magic-rod-rod_of_revolution-rod-of-revolution">Rod of Revolution</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 62</Link><br/><strong>Aura</strong> strong enchantment; <strong>CL</strong> 20th<br/><strong>Slot</strong> none; <strong>Price</strong> 82,000 gp; <strong>Weight</strong> 8 lbs.</p>
<p>This variant <Link to="/magic-rod/rod_of_rulership">rod of rulership</Link> looks like a castoff piece of wood from a lumber mill. Originating from the earliest insurrections of Galt, these rods have become symbolic among rebel leaders in the struggling nation. A rod of revolution's wielder can activate the device as a standard action to incite rebellious urges in creatures within 120 feet. The wielder can incite a number of creatures totaling 300 Hit Dice, but creatures with a Wisdom score of 12 or higher can attempt a DC 16 Will save to negate the effect. Incited creatures gain the benefits of the <em>rage</em> spell, but adhere to only the most basic commands issued by the wielder (such as directions about where to move and who to attack). The rod can be used for 500 total minutes before it crumbles to dust. These minutes need not be continuous.</p>
<h3 id="magic-rod-rod_of_revolution-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/mass_charm_monster">mass charm monster</Link>, <Link to="/spell/rage">rage</Link>; <strong>Cost</strong> 41,000 gp</p>
</>};
const _rod_of_alertness = {title: "Rod of Alertness", jsx: <><h2 id="magic-rod-rod_of_alertness-rod-of-alertness">Rod of Alertness</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 180</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 485</Link><br/><strong>Aura</strong> moderate varies; <strong>CL</strong> 11th<br/><strong>Slot</strong> none; <strong>Price</strong> 85,000 gp; <strong>Weight</strong> 4 lbs.</p>
<p>This rod is indistinguishable from a +1 <Link to="/eq-weapon/light_mace">light mace</Link>. The rod bestows a +1 insight bonus on initiative checks. If grasped firmly, it enables the wielder to use <em>detect chaos, detect evil, detect good, detect law, detect magic, discern lies, light,</em> or <em>see invisibility.</em> Each different use is a standard action.</p>
<p>If the head of a rod of alertness is planted in the ground and the possessor wills it to alertness (a standard action), the rod senses any creatures within 120 feet that intend to harm the possessor. At the same time, the rod creates the effect of a <em>prayer</em> spell upon all creatures friendly to the possessor in a 20-foot radius. Immediately thereafter, the rod sends forth a mental alert to these friendly creatures, warning them of any unfriendly creatures within the 120-foot radius. These effects last for 10 minutes, and the rod can perform this function once per day. Last, the rod can be used to simulate the casting of an <em>animate objects</em> spell, utilizing any 11 (or fewer) Small objects located roughly around the perimeter of a 5-foot-radius circle centered on the rod when planted in the ground. Objects remain animated for 11 rounds. The rod can perform this function once per day.</p>
<h3 id="magic-rod-rod_of_alertness-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/alarm">alarm</Link>, <Link to="/spell/animate_objects">animate objects</Link>, <Link to="/spell/prayer">prayer</Link>, <Link to="/spell/detect_evil">detect chaos, detect evil detect good, detect law</Link>, <Link to="/spell/detect_magic">detect magic</Link>, <Link to="/spell/discern_lies">discern lies</Link>, <Link to="/spell/light">light</Link>, <Link to="/spell/see_invisibility">see invisibility</Link>; <strong>Cost</strong> 42,500 gp</p>
</>};
const _dolorous_rod = {title: "Dolorous Rod", jsx: <><h2 id="magic-rod-dolorous_rod-dolorous-rod">Dolorous Rod</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 150</Link><br/><strong>Aura</strong> moderate enchantment and necromancy; <strong>CL</strong> 10th<br/><strong>Slot</strong> none; <strong>Price</strong> 120,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>On command, this rod beats with a slow, steady pulse, sending a deep, almost inaudible thrum through the air. At the start of each successive round of holding the rod, its bearer takes 1d10 points of damage that can't be reduced in any way, and must succeed at a DC 20 Fortitude save or gain a permanent <Link to="/rule/negative_level">negative level</Link>. While the rod is held, creatures within 120 feet take a -2 penalty on attack rolls, saving throws, ability checks, skill checks, and weapon damage rolls. This is a mind-affecting emotion effect. While held by a mythic creature, the rod prevents all creatures of an equal or lower mythic tier within its radius from expending mythic power. Mythic abilities that don't require expending uses of mythic power are unaffected.</p>
<h3 id="magic-rod-dolorous_rod-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/bestow_curse">bestow curse</Link>, <Link to="/spell/crushing_despair">crushing despair</Link>; <strong>Cost</strong> 60,000 gp</p>
</>};
const _hollow_rod = {title: "Hollow Rod", jsx: <><h2 id="magic-rod-hollow_rod-hollow-rod">Hollow Rod</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 254</Link><br/><strong>Aura</strong> strong (no school); <strong>CL</strong> 15th<br/><strong>Slot</strong> none; <strong>Price</strong> 121,500 gp; <strong>Weight</strong> 5 lbs.</p>
<p>Slightly smaller and shorter than <Link to="/magic-staff/vril_staff">vril staves</Link>, hollow rods are hollow silver tubes covered in intricate glyphs and small, flute-like keys. Three times per day, a <Link to="/class/kineticist">kineticist</Link> can utilize the hollow rod in conjunction with a blast wild talent or the <Link to="/kinetic/kinetic_healer">kinetic healer</Link> wild talent to augment that talent's destructive or healing capabilities, treating the wild talent as <Link to="/feat/maximized">maximized</Link>. A hollow rod can't be used on a wild talent affected by metakinesis.</p>
<h3 id="magic-rod-hollow_rod-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, creator must be a 10th-level kineticist; <strong>Cost</strong> 60,750 gp</p>
</>};
const _caduceus_rod = {title: "Caduceus Rod", jsx: <><h2 id="magic-rod-caduceus_rod-caduceus-rod">Caduceus Rod</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 253</Link><br/><strong>Aura</strong> strong conjuration and transmutation; <strong>CL</strong> 12th<br/><strong>Slot</strong> none; <strong>Price</strong> 142,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>Two entwined wooden snakes run the length of this laurel rod, which is capped with a pair of brass wings. This mystical implement gives its possessor a +5 insight bonus on <Link to="/skill/craft">Craft (alchemy)</Link> checks and a +1 insight bonus on attack and damage rolls with alchemical items, including <Link to="/class/alchemist">alchemists'</Link> bombs. When it's held in hand, the caduceus rod can be invoked five times per day to grant one of the following boons, each of which counts as a 6th-level spell-like ability.</p>
<p><strong className="hl">Awaken:</strong> The rod awakens all sleeping creatures within a 40-foot-radius <Link to="/misc/burst">burst</Link> centered on the wielder. Creatures in the burst gain immunity to sleep effects for 1 minute.</p>
<p><strong className="hl">Exchange:</strong> The wielder transmutes one of his prepared alchemical extracts into an extract of another formula in his formula book of equal or lower level.</p>
<p><strong className="hl">Mercy:</strong> All <Link to="/misc/dying">dying</Link> (-1 or fewer hit points) creatures in a 40-foot-radius burst centered on the wielder die. Each such creature can attempt a DC 19 Fortitude save to instead take 1d6 points of negative energy damage. This is a death effect.</p>
<p><strong className="hl">Revive:</strong> The wielder targets a creature within 40 feet with <Link to="/feat/empowered">empowered</Link> <em>breath of life.</em></p>
<p><strong className="hl">Slumber:</strong> As <em>deep slumber,</em> except that it affects a 20-foot-radius burst centered on the wielder, can affect up to 20 HD of creatures, and has a Will save DC of 19. The wielder of the rod is unaffected and can choose to exclude up to four other targets from the effects.</p>
<h3 id="magic-rod-caduceus_rod-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/breath_of_life">breath of life</Link>, <Link to="/spell/deep_slumber">deep slumber</Link>, <Link to="/spell/heroism">heroism</Link>, <Link to="/spell/universal_formula">universal formula</Link>, creator must have at least 10 ranks in Craft (alchemy); <strong>Cost</strong> 71,000 gp</p>
</>};
const _scepter_of_the_arclords = {title: "Scepter of the Arclords", jsx: <><h2 id="magic-rod-scepter_of_the_arclords-scepter-of-the-arclords">Scepter of the Arclords</h2>
<p><strong>Sources</strong> <Link to="/source/lost_treasures">Lost Treasures pg. 52</Link><br/><strong>Aura</strong> strong universal; <strong>CL</strong> 20th<br/><strong>Slot</strong> none; <strong>Price</strong> 200,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>The Scepter of the Arclords is a powerful device capable of harvesting all the ambient magic from a large area and focusing it into a single powerful effect. Once per day the wielder can command the Scepter of the Arclords to duplicate any spell of 3rd level or lower. This automatically succeeds, but there is a 10% chance the wielder also gains a random minor <Link to="/rule/spellblights">spellblight</Link>.</p>
<p>Additionally, once per week the wielder can command the item to create any magic effect he desires. Roll d% to determine the effect of this command.</p>
<ScrollContainer id="magic-rod-scepter_of_the_arclords--table-0"><table>
<thead>
<tr>
<th>d%</th>
<th>Effect</th>
</tr>
</thead>
<tbody><tr>
<td>01</td>
<td>The wielder gains a major spellblight. The GM may determine the spellblight randomly, or may design a custom spellblight based on the magic effect the wielder commanded the scepter to create. The DC to remove this spellblight (using the normal rules for eliminating spellblights) is 35 (or 40, if the target still has the Scepter of the Arclords in his possession), and isn't reduced with the passage of time.</td>
</tr>
<tr>
<td>02-05</td>
<td>The Scepter creates a permanently magic-dead area with a radius of d% &times; 100 feet.</td>
</tr>
<tr>
<td>06-10</td>
<td>The Scepter creates a permanent area of <Link to="/rule/primal_magic">primal magic</Link> with a radius of d% &times; 100 feet.</td>
</tr>
<tr>
<td>11-80</td>
<td>The wielder's command is fulfilled with a <em>limited wish.</em> If a limited wish can't fulfill the command, the scepter comes as close to fulfilling it as a <em>limited wish</em> can (GM's discretion).</td>
</tr>
<tr>
<td>81-100</td>
<td>The wielder's command is fulfilled with a <em>wish.</em> If a <em>wish</em> can't fulfill the command, the scepter comes as close to fulfilling it as a <em>wish</em> can (GM's discretion). Additionally, one random creature of the outsider type learns the wielder has the scepter and just used it to gain a <em>wish;</em> the nature of the <em>wish</em> and the location of the wielder aren't revealed. The GM secretly determines which outsider gains this knowledge.</td>
</tr>
</tbody></table></ScrollContainer>
<p>The eye-like spheres on the Scepter sometimes swivel of their own accord, and although the Scepter isn't intelligent, it's capable of sliding on its own at a speed of 5 feet.</p>
<h3 id="magic-rod-scepter_of_the_arclords-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_rod">Craft Rod</Link>, <Link to="/spell/limited_wish">limited wish</Link>, <Link to="/spell/wish">wish</Link>; <strong>Cost</strong> 100,000 gp</p>
</>};
